#!/usr/bin/env npx tsx
/**
 * add-authors.ts
 *
 * Adds missing author entries to authors.ts for all books in the catalog.
 * Reads books.ts to find all unique authorId values, checks which are missing
 * from authors.ts, and generates entries for them.
 *
 * Run: npx tsx scripts/add-authors.ts
 */

import * as fs from "fs";
import * as path from "path";

const ROOT = path.resolve(__dirname, "..");
const BOOKS_FILE = path.join(ROOT, "src/data/books.ts");
const AUTHORS_FILE = path.join(ROOT, "src/data/authors.ts");

// ── Author metadata keyed by authorId ────────────────────────────────────────
// Each entry: [name, birthYear, deathYear, birthPlace, nationality, era, traditions[], bio, notableWorks[], themes[], influence, funFact, quotes[], gradient]

interface AuthorConfig {
  id: string;
  name: string;
  birthYear?: number;
  deathYear?: number;
  birthPlace: string;
  nationality: string;
  era: string;
  traditions: string[];
  bio: string;
  notableWorks: string[];
  themes: string[];
  influence: string;
  funFact: string;
  quotes: string[];
  portraitPlaceholder: string;
}

const AUTHORS: AuthorConfig[] = [
  // ── Ancient ────────────────────────────────────────────────────────────────
  { id: "aeschylus", name: "Aeschylus", birthYear: -525, deathYear: -456, birthPlace: "Eleusis, Attica, Ancient Greece", nationality: "Greek", era: "Ancient", traditions: ["Ancient Greek"], bio: "Aeschylus is often called the father of tragedy. He fought at the Battle of Marathon and transformed the nascent art form by introducing a second actor, enabling true dramatic dialogue. Of the approximately seventy to ninety plays he wrote, only seven survive, including the Oresteia trilogy — the only complete Greek tragic trilogy we possess.\n\nHis plays grapple with cosmic justice, the relationship between mortals and gods, and the transition from blood vengeance to civic law. The Oresteia traces the House of Atreus from Agamemnon's murder through Orestes' matricide to Athena's establishment of the jury trial, enacting nothing less than the birth of democratic justice from the ruins of cyclical violence.", notableWorks: ["The Oresteia", "Prometheus Bound", "The Persians", "Seven Against Thebes"], themes: ["Justice", "Fate", "Divine law", "Civilization", "Suffering", "Transformation"], influence: "Aeschylus invented the conventions of Western tragic drama and gave civilization its founding myth of justice replacing vengeance.", funFact: "Ancient tradition holds that Aeschylus was killed when an eagle dropped a tortoise on his bald head, mistaking it for a rock.", quotes: ["He who learns must suffer.", "In war, truth is the first casualty.", "Wisdom comes through suffering."], portraitPlaceholder: "linear-gradient(135deg, #1E3A5F, #0F2744)" },
  { id: "apollonius-of-rhodes", name: "Apollonius of Rhodes", birthYear: -295, deathYear: -215, birthPlace: "Alexandria, Egypt", nationality: "Greek", era: "Ancient", traditions: ["Ancient Greek"], bio: "Apollonius served as head of the Library of Alexandria and composed the Argonautica, the great Hellenistic epic that retells Jason's quest for the Golden Fleece. Unlike Homer's heroes, Apollonius's Jason is uncertain and dependent on others — particularly the sorceress Medea, whose passionate inner life makes her the poem's true protagonist.\n\nThe Argonautica bridges Homer and Virgil, introducing psychological complexity and romantic love as epic subjects. Medea's anguished monologues influenced Virgil's Dido and, through her, the entire tradition of tragic heroines in Western literature.", notableWorks: ["Argonautica"], themes: ["Love", "Quest", "Heroism", "Magic", "The sea", "Psychology"], influence: "The Argonautica made romantic love a legitimate subject for epic poetry and directly shaped Virgil's portrayal of Dido in the Aeneid.", funFact: "Apollonius may have been forced out of Alexandria by a literary feud with his teacher Callimachus over the proper length of poetry.", quotes: ["Love is a great teacher.", "Bold is the venture of the brave."], portraitPlaceholder: "linear-gradient(135deg, #1E3A5F, #0F2744)" },
  { id: "apuleius", name: "Apuleius", birthYear: 124, deathYear: 170, birthPlace: "Madauros, Numidia (modern Algeria)", nationality: "Roman", era: "Ancient", traditions: ["Ancient Greek"], bio: "Apuleius was a North African author, philosopher, and rhetorician writing in Latin during the Roman Empire. His masterpiece, The Golden Ass (Metamorphoses), is the only Latin novel to survive complete and one of the earliest surviving novels in any language.\n\nThe story of a man transformed into a donkey through magical misadventure combines bawdy comedy, adventure, satire, and mystical revelation. Embedded within it is the exquisite tale of Cupid and Psyche, one of the most retold stories in Western culture. The novel's final book, describing the narrator's conversion to the cult of Isis, shifts abruptly from comedy to genuine religious experience.", notableWorks: ["The Golden Ass", "Apologia", "Florida"], themes: ["Transformation", "Curiosity", "Religion", "Satire", "Magic", "Redemption"], influence: "The Golden Ass is the earliest fully surviving novel and a direct ancestor of the picaresque tradition from Cervantes to Fielding.", funFact: "Apuleius was put on trial for winning his wife's affections through magic — his defense speech survives as the Apologia.", quotes: ["Curiosity is the beginning of wisdom.", "Fortune is not only blind but mad."], portraitPlaceholder: "linear-gradient(135deg, #1E3A5F, #0F2744)" },
  { id: "thucydides", name: "Thucydides", birthYear: -460, deathYear: -400, birthPlace: "Athens, Ancient Greece", nationality: "Greek", era: "Ancient", traditions: ["Ancient Greek"], bio: "Thucydides wrote the History of the Peloponnesian War, the conflict between Athens and Sparta that consumed the Greek world from 431 to 404 BCE. An Athenian general himself, he was exiled after a military failure and spent twenty years observing and recording the war with unprecedented analytical rigor.\n\nHe rejected divine causation and mythology in favor of human psychology and political analysis, making his work the foundation of both political science and modern historiography. His account of the Plague of Athens, Pericles' Funeral Oration, and the Melian Dialogue remain among the most studied texts in political thought.", notableWorks: ["History of the Peloponnesian War"], themes: ["War", "Power", "Democracy", "Human nature", "Imperialism", "Justice"], influence: "Thucydides invented evidence-based historical analysis and remains required reading in international relations and military strategy.", funFact: "His History breaks off mid-sentence in 411 BCE — he likely died before completing it.", quotes: ["The strong do what they can.", "War is a stern teacher."], portraitPlaceholder: "linear-gradient(135deg, #1E3A5F, #0F2744)" },

  // ── Renaissance & Early Modern ─────────────────────────────────────────────
  { id: "christopher-marlowe", name: "Christopher Marlowe", birthYear: 1564, deathYear: 1593, birthPlace: "Canterbury, England", nationality: "English", era: "Renaissance", traditions: ["Renaissance"], bio: "Christopher Marlowe was Shakespeare's exact contemporary and greatest rival, a Cambridge-educated playwright and probable spy who pioneered blank verse on the English stage. His plays — Tamburlaine, Doctor Faustus, The Jew of Malta — blaze with rhetorical power and transgressive ambition.\n\nMarlowe's protagonists are overreachers who defy every boundary: Tamburlaine conquers the known world, Faustus sells his soul for knowledge, Barabas accumulates wealth beyond measure. Their inevitable destruction creates a dramatic pattern that Shakespeare would inherit and complicate. Marlowe was stabbed to death at twenty-nine in circumstances that remain mysterious.", notableWorks: ["Doctor Faustus", "Tamburlaine", "The Jew of Malta", "Edward II"], themes: ["Ambition", "Transgression", "Power", "Knowledge", "Damnation", "Desire"], influence: "Marlowe established blank verse as the medium of English drama and created the overreacher protagonist that Shakespeare perfected.", funFact: "He was killed in a Deptford tavern, officially in a dispute over the bill, but many suspect it was an assassination connected to his intelligence work.", quotes: ["Was this the face that launched a thousand ships?", "Hell is just a frame of mind."], portraitPlaceholder: "linear-gradient(135deg, #3D1A6E, #2A1050)" },
  { id: "edmund-spenser", name: "Edmund Spenser", birthYear: 1552, deathYear: 1599, birthPlace: "London, England", nationality: "English", era: "Renaissance", traditions: ["Renaissance"], bio: "Edmund Spenser's The Faerie Queene is the greatest long poem of the English Renaissance, an intricate allegorical epic that blends Arthurian romance, Protestant theology, and praise of Queen Elizabeth into a tapestry of extraordinary beauty and moral complexity.\n\nSpenser invented a stanza form — the Spenserian stanza — that would be used by Keats, Byron, and Shelley centuries later. His archaized language and dreamlike narrative influenced Milton, the Romantics, and Tolkien.", notableWorks: ["The Faerie Queene", "The Shepheardes Calender", "Amoretti"], themes: ["Virtue", "Allegory", "Romance", "Faith", "Beauty", "Chivalry"], influence: "Spenser's Faerie Queene shaped the entire tradition of English allegorical and fantasy literature from Bunyan to Tolkien.", funFact: "Spenser's castle in Ireland was burned during a rebellion; tradition says an infant child perished in the fire.", quotes: ["Sleep after toil, port after stormy seas.", "It is the mind that maketh good or ill."], portraitPlaceholder: "linear-gradient(135deg, #3D1A6E, #2A1050)" },

  // ── Enlightenment ──────────────────────────────────────────────────────────
  { id: "daniel-defoe", name: "Daniel Defoe", birthYear: 1660, deathYear: 1731, birthPlace: "London, England", nationality: "English", era: "Enlightenment", traditions: ["Enlightenment"], bio: "Daniel Defoe was a journalist, pamphleteer, spy, and novelist whose Robinson Crusoe (1719) is often called the first English novel. A Dissenter who spent time in prison for his writings, Defoe brought a journalist's eye for concrete detail to fiction, creating narratives so convincingly realistic that readers took them for true accounts.\n\nBeyond Crusoe, his Journal of the Plague Year recreates the Great Plague of 1665 with documentary vividness, and Moll Flanders follows a woman through crime, prostitution, and transportation with unsentimental sympathy. Defoe wrote with extraordinary prolificacy — over 300 works across his career.", notableWorks: ["Robinson Crusoe", "Moll Flanders", "A Journal of the Plague Year", "Roxana"], themes: ["Survival", "Self-reliance", "Commerce", "Sin", "Redemption", "Urban life"], influence: "Defoe pioneered the realistic novel in English and established journalism as a literary form.", funFact: "He was pilloried for seditious libel but the crowd threw flowers instead of rotten vegetables.", quotes: ["Fear of danger is ten thousand times more terrifying than danger itself.", "The best of men cannot suspend their fate."], portraitPlaceholder: "linear-gradient(135deg, #0F2744, #091A2E)" },
  { id: "henry-fielding", name: "Henry Fielding", birthYear: 1707, deathYear: 1754, birthPlace: "Sharpham, Somerset, England", nationality: "English", era: "Enlightenment", traditions: ["Enlightenment"], bio: "Henry Fielding was a playwright turned novelist who, along with Samuel Richardson, established the English novel as a major literary form. His masterpiece Tom Jones is a vast, exuberant comic novel that follows a foundling's picaresque adventures through every level of 18th-century English society.\n\nFielding brought wit, irony, and a generous moral vision to fiction. He also founded the Bow Street Runners, London's first professional police force, making him one of the few great novelists who also helped invent modern law enforcement.", notableWorks: ["Tom Jones", "Joseph Andrews", "Shamela", "Amelia"], themes: ["Virtue", "Hypocrisy", "Comic epic", "Class", "Justice", "Human nature"], influence: "Tom Jones established the comic novel as a major genre and influenced Dickens, Thackeray, and the entire tradition of English social fiction.", funFact: "He founded the Bow Street Runners, London's first professional police force.", quotes: ["A good face is a letter of recommendation.", "Fashion is the great governor of this world."], portraitPlaceholder: "linear-gradient(135deg, #0F2744, #091A2E)" },
  { id: "oliver-goldsmith", name: "Oliver Goldsmith", birthYear: 1728, deathYear: 1774, birthPlace: "Pallas, County Longford, Ireland", nationality: "Irish", era: "Enlightenment", traditions: ["Enlightenment"], bio: "Oliver Goldsmith was an Irish-born writer who excelled in every literary form — novel, play, poem, and essay. The Vicar of Wakefield combines gentle satire with genuine pathos, She Stoops to Conquer remains one of the funniest plays in English, and The Deserted Village is a masterpiece of social protest poetry.\n\nDespite his literary brilliance, Goldsmith was famously improvident and socially awkward. Samuel Johnson, his close friend, wrote his epitaph praising a man who touched nothing he did not adorn.", notableWorks: ["The Vicar of Wakefield", "She Stoops to Conquer", "The Deserted Village"], themes: ["Rural life", "Virtue", "Comedy", "Social change", "Goodness", "Loss"], influence: "Goldsmith's humane comedy and pastoral elegance influenced Austen, Dickens, and the tradition of English gentle satire.", funFact: "Johnson said of him: He touched nothing that he did not adorn.", quotes: ["Ask me no questions, and I'll tell you no fibs.", "The best-laid schemes of mice and men often go awry."], portraitPlaceholder: "linear-gradient(135deg, #0F2744, #091A2E)" },
  { id: "horace-walpole", name: "Horace Walpole", birthYear: 1717, deathYear: 1797, birthPlace: "London, England", nationality: "English", era: "Enlightenment", traditions: ["Romantic"], bio: "Horace Walpole was the son of Britain's first Prime Minister and a prolific letter-writer, antiquarian, and Member of Parliament. His single novel, The Castle of Otranto (1764), invented the Gothic genre and changed the direction of English fiction.\n\nWalpole built Strawberry Hill, a faux-medieval villa that became the architectural embodiment of the Gothic Revival. Otranto, written after a dream about a giant armored hand, introduced supernatural terror, mysterious manuscripts, and gloomy castles to the novel — elements that would flow through Radcliffe, Lewis, the Brontës, Poe, and into modern horror.", notableWorks: ["The Castle of Otranto"], themes: ["Gothic", "The supernatural", "Antiquarianism", "Terror", "Inheritance", "Dreams"], influence: "Walpole single-handedly invented the Gothic novel, the most productive genre in English fiction for the next century.", funFact: "He coined the word 'serendipity' in a letter, based on the fairy tale The Three Princes of Serendip.", quotes: ["The world is a comedy to those that think.", "Life is a comedy for those who think."], portraitPlaceholder: "linear-gradient(135deg, #4A0E2D, #2D0819)" },
  { id: "laurence-sterne", name: "Laurence Sterne", birthYear: 1713, deathYear: 1768, birthPlace: "Clonmel, County Tipperary, Ireland", nationality: "Irish-English", era: "Enlightenment", traditions: ["Enlightenment"], bio: "Laurence Sterne was an Anglican clergyman whose Tristram Shandy is the most audaciously experimental novel of the 18th century. Its narrator cannot even manage to get born until Volume III, constantly digressing into anecdotes, opinions, and typographical experiments including a black page, a marbled page, and blank pages for the reader to fill in.\n\nSterne anticipated stream-of-consciousness, metafiction, and postmodernism by two centuries. His other major work, A Sentimental Journey, coined the term 'sentimental' for a new mode of travel writing focused on feeling rather than fact.", notableWorks: ["Tristram Shandy", "A Sentimental Journey"], themes: ["Digression", "Time", "Sentiment", "Comedy", "Metafiction", "Subjectivity"], influence: "Sterne's radical experiments with narrative form anticipated modernism and postmodernism by two hundred years.", funFact: "After his death, his body was stolen by grave robbers and recognized on an anatomy table at Cambridge.", quotes: ["I wrote not to be fed but to be famous.", "Digressions are the sunshine of reading."], portraitPlaceholder: "linear-gradient(135deg, #0F2744, #091A2E)" },
  { id: "samuel-richardson", name: "Samuel Richardson", birthYear: 1689, deathYear: 1761, birthPlace: "Mackworth, Derbyshire, England", nationality: "English", era: "Enlightenment", traditions: ["Enlightenment"], bio: "Samuel Richardson was a printer who became a novelist almost by accident when a commission to write a book of model letters evolved into Pamela (1740), one of the first true English novels. His masterpiece Clarissa — at over a million words, the longest novel in English — tells the story of a virtuous woman's destruction by a charming rake through letters of extraordinary psychological depth.\n\nRichardson's epistolary method created an unprecedented sense of immediacy and interiority. The novel as a form for exploring consciousness owes as much to Richardson as to anyone.", notableWorks: ["Clarissa", "Pamela", "Sir Charles Grandison"], themes: ["Virtue", "Seduction", "Class", "Psychology", "Letters", "Morality"], influence: "Richardson established the psychological novel and the epistolary form, directly influencing Rousseau, Laclos, and Austen.", funFact: "Clarissa is over a million words long — the longest novel in the English language.", quotes: ["A feeling heart is a blessing that no one who has it would be without.", "Calamity is the test of integrity."], portraitPlaceholder: "linear-gradient(135deg, #0F2744, #091A2E)" },
  { id: "thomas-paine", name: "Thomas Paine", birthYear: 1737, deathYear: 1809, birthPlace: "Thetford, Norfolk, England", nationality: "English-American", era: "Enlightenment", traditions: ["Enlightenment"], bio: "Thomas Paine was the most influential political pamphleteer of the Age of Revolution. Common Sense (1776) persuaded the American colonies that independence was both necessary and possible. The Rights of Man (1791) defended the French Revolution against Edmund Burke. The Age of Reason (1794) attacked organized religion with devastating logic.\n\nPaine wrote with a clarity and directness that made complex political ideas accessible to ordinary readers. He helped ignite two revolutions and articulate the principles of democratic government, yet died in poverty and obscurity, reviled by the religious establishment he had challenged.", notableWorks: ["Common Sense", "Rights of Man", "The Age of Reason", "The American Crisis"], themes: ["Liberty", "Revolution", "Reason", "Democracy", "Religion", "Rights"], influence: "Paine's pamphlets were instrumental in both the American and French Revolutions and established political journalism as a force for change.", funFact: "Only six people attended his funeral — America had largely forgotten the man who helped create it.", quotes: ["These are the times that try men's souls.", "My country is the world."], portraitPlaceholder: "linear-gradient(135deg, #0F2744, #091A2E)" },
  { id: "john-locke", name: "John Locke", birthYear: 1632, deathYear: 1704, birthPlace: "Wrington, Somerset, England", nationality: "English", era: "Enlightenment", traditions: ["Enlightenment"], bio: "John Locke was the philosopher whose ideas about natural rights, government by consent, and the social contract became the intellectual foundation of liberal democracy. His Two Treatises of Government argued that sovereignty resides in the people, not the monarch — ideas that directly shaped the American Declaration of Independence.\n\nHis Essay Concerning Human Understanding proposed that the mind at birth is a blank slate (tabula rasa), making experience and education the sources of all knowledge. This empiricism influenced everything from psychology to pedagogy.", notableWorks: ["Two Treatises of Government", "Essay Concerning Human Understanding", "Letter Concerning Toleration"], themes: ["Liberty", "Knowledge", "Government", "Rights", "Education", "Tolerance"], influence: "Locke's political philosophy provided the theoretical foundation for the American Revolution and modern constitutional democracy.", funFact: "He helped draft the constitution for the Carolina colonies, which included provisions for religious tolerance.", quotes: ["No man's knowledge can go beyond his experience.", "Government has no other end but the preservation of property."], portraitPlaceholder: "linear-gradient(135deg, #0F2744, #091A2E)" },
  { id: "thomas-hobbes", name: "Thomas Hobbes", birthYear: 1588, deathYear: 1679, birthPlace: "Westport, Wiltshire, England", nationality: "English", era: "Renaissance", traditions: ["Enlightenment"], bio: "Thomas Hobbes wrote Leviathan (1651), one of the foundational texts of Western political philosophy. Writing during the English Civil War, he argued that human beings in a state of nature live in constant fear and that only an absolute sovereign can maintain peace and order.\n\nHis famous description of life without government as 'solitary, poor, nasty, brutish, and short' remains one of the most quoted phrases in political theory. Whether one agrees with his conclusions or not, all subsequent political philosophy has had to reckon with his challenge.", notableWorks: ["Leviathan", "De Cive", "Behemoth"], themes: ["Power", "Authority", "Human nature", "Social contract", "Fear", "Order"], influence: "Hobbes founded modern political philosophy and the social contract tradition that runs through Locke, Rousseau, and Rawls.", funFact: "He reportedly said his mother gave birth to twins — himself and fear — when the Spanish Armada was approaching.", quotes: ["Life is nasty, brutish, and short.", "Words are wise men's counters."], portraitPlaceholder: "linear-gradient(135deg, #0F2744, #091A2E)" },
  { id: "adam-smith", name: "Adam Smith", birthYear: 1723, deathYear: 1790, birthPlace: "Kirkcaldy, Fife, Scotland", nationality: "Scottish", era: "Enlightenment", traditions: ["Enlightenment"], bio: "Adam Smith was a moral philosopher whose Wealth of Nations (1776) founded the science of economics. He argued that free markets, guided by the 'invisible hand' of self-interest, produce greater prosperity than government planning — an insight that transformed the modern world.\n\nBut Smith was no simple apostle of greed. His earlier Theory of Moral Sentiments grounded ethics in human sympathy, and the Wealth of Nations itself contains sharp critiques of merchants, monopolists, and the exploitation of workers. The real Smith is far more nuanced than either his champions or critics suggest.", notableWorks: ["The Wealth of Nations", "The Theory of Moral Sentiments"], themes: ["Economics", "Markets", "Sympathy", "Labor", "Justice", "Society"], influence: "Smith founded modern economics and established the framework for understanding markets, trade, and the division of labor.", funFact: "He was so absent-minded that he once fell into a tanning pit while walking and talking.", quotes: ["It is not from the benevolence of the butcher that we expect our dinner.", "No society can be flourishing and happy when the greater part of its members are poor."], portraitPlaceholder: "linear-gradient(135deg, #0F2744, #091A2E)" },
  { id: "john-stuart-mill", name: "John Stuart Mill", birthYear: 1806, deathYear: 1873, birthPlace: "Pentonville, London, England", nationality: "English", era: "19th Century", traditions: ["Victorian"], bio: "John Stuart Mill was the most influential English-speaking philosopher of the 19th century. On Liberty (1859) remains the definitive defense of individual freedom against state and social tyranny. His Subjection of Women (1869) was one of the earliest major feminist philosophical texts.\n\nEducated by his father in an extraordinary hothouse regimen (Greek at three, Latin at eight), Mill suffered a severe mental crisis at twenty before recovering through poetry and emotion. His autobiography traces this journey from pure rationalism to a richer understanding of human flourishing.", notableWorks: ["On Liberty", "Utilitarianism", "The Subjection of Women", "Autobiography"], themes: ["Liberty", "Utility", "Gender equality", "Democracy", "Individual rights", "Progress"], influence: "Mill's On Liberty defined the limits of legitimate authority over the individual and remains the touchstone of liberal political thought.", funFact: "He was arrested at age seventeen for distributing birth control pamphlets.", quotes: ["The only freedom deserving the name is that of pursuing our own good in our own way.", "Ask yourself whether you are happy, and you cease to be so."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },

  // ── Victorian ──────────────────────────────────────────────────────────────
  { id: "arthur-conan-doyle", name: "Arthur Conan Doyle", birthYear: 1859, deathYear: 1930, birthPlace: "Edinburgh, Scotland", nationality: "British", era: "19th Century", traditions: ["Victorian"], bio: "Sir Arthur Conan Doyle created Sherlock Holmes, the most famous fictional detective in history and a character who has never been out of print since his first appearance in A Study in Scarlet (1887). A physician by training, Doyle modeled Holmes's deductive method on his Edinburgh professor Joseph Bell.\n\nDoyle regarded Holmes as a distraction from his 'serious' historical novels and twice tried to kill him off, but public demand forced his resurrection. Beyond Holmes, he wrote the Professor Challenger science fiction novels, historical romances, and was a passionate advocate for spiritualism in his later years.", notableWorks: ["The Adventures of Sherlock Holmes", "The Hound of the Baskervilles", "A Study in Scarlet", "The Lost World"], themes: ["Deduction", "Justice", "Science", "Crime", "Friendship", "The rational"], influence: "Doyle established the modern detective story and created the most recognizable fictional character in world literature.", funFact: "He tried to kill Holmes at Reichenbach Falls but public outrage — including mourning armbands — forced him to bring the detective back.", quotes: ["When you have eliminated the impossible, whatever remains must be the truth.", "The world is full of obvious things which nobody observes."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "anthony-trollope", name: "Anthony Trollope", birthYear: 1815, deathYear: 1882, birthPlace: "London, England", nationality: "English", era: "19th Century", traditions: ["Victorian"], bio: "Anthony Trollope wrote forty-seven novels while maintaining a full career at the Post Office (where he invented the pillar box). His two great series — the six Barsetshire novels chronicling clerical life and the six Palliser novels exploring political life — together form the most sustained and psychologically detailed panorama of Victorian England.\n\nTrollope's great gift is his absolute refusal to simplify human beings. His characters are never purely good or evil; they muddle through life making compromises, and the reader comes to understand and sympathize with almost all of them. Henry James called him 'a novelist who hunted the fox all day and came home to write at night.'", notableWorks: ["Barchester Towers", "The Way We Live Now", "The Last Chronicle of Barset", "Can You Forgive Her?"], themes: ["Clergy", "Politics", "Marriage", "Money", "Ambition", "Community"], influence: "Trollope's patient, humane realism made him the Victorians' supreme chronicler of everyday moral life and influenced novelists from James to Barnes.", funFact: "He wrote 250 words every 15 minutes before breakfast, and if he finished a novel mid-session, he immediately started the next one.", quotes: ["There is no happiness in love except at the end of an English novel.", "A man's mind will very generally refuse to make itself up until it be driven and compelled by emergency."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "elizabeth-gaskell", name: "Elizabeth Gaskell", birthYear: 1810, deathYear: 1865, birthPlace: "Chelsea, London, England", nationality: "English", era: "19th Century", traditions: ["Victorian"], bio: "Elizabeth Gaskell was a novelist whose industrial novels — Mary Barton and North and South — gave voice to the working poor of Manchester with an empathy and authenticity that rivaled Dickens. Her Cranford is a comic masterpiece of provincial feminine life, and her biography of Charlotte Brontë remains one of the great literary biographies.\n\nGaskell combined social conscience with psychological insight and narrative skill. She was one of the few Victorian novelists equally at home in industrial realism, social comedy, and Gothic tales.", notableWorks: ["North and South", "Cranford", "Mary Barton", "Wives and Daughters"], themes: ["Class", "Industry", "Community", "Women's lives", "Social reform", "Provincial life"], influence: "Gaskell pioneered the industrial novel and created some of the most vivid portraits of Victorian women's domestic and public lives.", funFact: "She died suddenly mid-sentence while having tea — literally in the middle of telling a story.", quotes: ["A little credulity helps one through life.", "Sometimes one likes foolish people for their folly."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "thomas-hardy", name: "Thomas Hardy", birthYear: 1840, deathYear: 1928, birthPlace: "Higher Bockhampton, Dorset, England", nationality: "English", era: "19th Century", traditions: ["Victorian"], bio: "Thomas Hardy set his novels and poems in the fictional Wessex, a rural England being destroyed by industrialization and modernity. His great novels — Far from the Madding Crowd, The Mayor of Casterbridge, Tess of the d'Urbervilles, Jude the Obscure — portray characters trapped between desire and convention, nature and society, fate and free will.\n\nThe hostile reception of Jude the Obscure (a bishop burned it publicly) convinced Hardy to abandon fiction for poetry, and his final thirty years produced some of the finest verse of the 20th century. His vision is tragic but never cynical — he mourns what his characters suffer.", notableWorks: ["Tess of the d'Urbervilles", "Far from the Madding Crowd", "Jude the Obscure", "The Mayor of Casterbridge"], themes: ["Fate", "Rural life", "Modernity", "Sexuality", "Class", "Tragedy"], influence: "Hardy bridged Victorian and modern literature, bringing an unflinching naturalism to the novel that anticipated Lawrence and the modernists.", funFact: "After his death, his heart was buried in Dorset while the rest of him was cremated and placed in Westminster Abbey.", quotes: ["Time changes everything except something within us which is always surprised by change.", "If way to the better there be, it exacts a full look at the worst."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "h-g-wells", name: "H. G. Wells", birthYear: 1866, deathYear: 1946, birthPlace: "Bromley, Kent, England", nationality: "English", era: "19th Century", traditions: ["Victorian"], bio: "H. G. Wells invented modern science fiction with a remarkable series of novels in the 1890s: The Time Machine, The Island of Doctor Moreau, The Invisible Man, and The War of the Worlds each introduced a premise that has never stopped being retold. But Wells was equally accomplished as a social novelist — Kipps and Tono-Bungay are among the best Edwardian novels.\n\nA lower-middle-class boy who won a scholarship to study under T. H. Huxley, Wells combined scientific imagination with social criticism and an urgent belief in human progress. His later works grew increasingly didactic, but his early fiction retains its power to terrify and illuminate.", notableWorks: ["The Time Machine", "The War of the Worlds", "The Invisible Man", "The Island of Doctor Moreau", "Tono-Bungay"], themes: ["Science", "Evolution", "Class", "Progress", "Utopia", "The future"], influence: "Wells established the conventions of science fiction and used speculative scenarios to critique Victorian and Edwardian society.", funFact: "He proposed the idea of a world encyclopedia — a 'World Brain' — that eerily anticipated the internet.", quotes: ["If we don't end war, war will end us.", "Adapt or perish is nature's inexorable imperative."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "robert-louis-stevenson", name: "Robert Louis Stevenson", birthYear: 1850, deathYear: 1894, birthPlace: "Edinburgh, Scotland", nationality: "Scottish", era: "19th Century", traditions: ["Victorian"], bio: "Robert Louis Stevenson was a novelist, poet, essayist, and travel writer whose Treasure Island and Strange Case of Dr Jekyll and Mr Hyde are among the most famous stories in English. A lifelong invalid who traveled the world seeking health, he settled in Samoa where he was revered by the islanders as Tusitala — 'the teller of tales.'\n\nStevenson combined narrative mastery with psychological depth. Jekyll and Hyde is both a cracking thriller and a profound meditation on duality; Kidnapped and The Master of Ballantrae bring the Scottish landscape alive with the force of lived experience.", notableWorks: ["Treasure Island", "Strange Case of Dr Jekyll and Mr Hyde", "Kidnapped", "The Master of Ballantrae"], themes: ["Duality", "Adventure", "Scotland", "Morality", "Travel", "Identity"], influence: "Stevenson proved that adventure fiction could be great literature and created the definitive modern exploration of human duality.", funFact: "The Samoan people built a road to carry his coffin to the top of Mount Vaea, where he is still buried.", quotes: ["To travel hopefully is a better thing than to arrive.", "Everyone lives by selling something."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "bram-stoker", name: "Bram Stoker", birthYear: 1847, deathYear: 1912, birthPlace: "Clontarf, Dublin, Ireland", nationality: "Irish", era: "19th Century", traditions: ["Victorian"], bio: "Bram Stoker was an Irish author and theatrical manager best known for Dracula (1897), the novel that defined the modern vampire and became one of the most influential horror stories ever written. Stoker spent years researching Eastern European folklore and compiled his novel in an epistolary format of letters, diary entries, and newspaper clippings.\n\nDracula synthesizes Victorian anxieties about sexuality, immigration, modernity, and contagion into a mythic narrative that has never lost its grip on the popular imagination.", notableWorks: ["Dracula", "The Lair of the White Worm", "The Jewel of Seven Stars"], themes: ["Horror", "Sexuality", "Modernity", "Good vs. evil", "Empire", "Death"], influence: "Stoker's Dracula is the most adapted novel in history and defined the vampire as a figure of erotic menace in Western culture.", funFact: "He managed the Lyceum Theatre for the great actor Henry Irving for 27 years while writing novels on the side.", quotes: ["The blood is the life.", "Listen to them, the children of the night."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "wilkie-collins", name: "Wilkie Collins", birthYear: 1824, deathYear: 1889, birthPlace: "London, England", nationality: "English", era: "19th Century", traditions: ["Victorian"], bio: "Wilkie Collins was the inventor of the English detective novel and sensation fiction. The Woman in White (1859) and The Moonstone (1868) pioneered multiple-narrator storytelling, elaborate plotting, and the marriage of mystery with social criticism that would become the backbone of English popular fiction.\n\nDickens's close friend and collaborator, Collins was in many ways more technically innovative. T. S. Eliot called The Moonstone the first and greatest English detective novel.", notableWorks: ["The Woman in White", "The Moonstone", "No Name", "Armadale"], themes: ["Mystery", "Identity", "Law", "Women's rights", "Sensation", "Justice"], influence: "Collins invented the detective novel and sensation fiction, establishing the genres that dominate popular literature to this day.", funFact: "He maintained two separate households with two different women for most of his adult life.", quotes: ["The best men are not consistent in good.", "I have always held the old-fashioned opinion that the primary object of a work of fiction should be to tell a story."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "george-eliot", name: "George Eliot", fullName: "Mary Ann Evans", birthYear: 1819, deathYear: 1880, birthPlace: "Nuneaton, Warwickshire, England", nationality: "English", era: "19th Century", traditions: ["Victorian"], bio: "George Eliot was the pen name of Mary Ann Evans, the greatest English novelist of the Victorian era. Middlemarch — described by Virginia Woolf as one of the few English novels written for grown-up people — is a vast study of provincial life that weaves together the stories of an idealistic young woman, an ambitious doctor, a hypocritical banker, and an entire community.\n\nEliot brought a philosophical intelligence and moral seriousness to the novel that had no precedent. She understood the web of social relations that constrain individual aspiration, and her sympathy extended to every character, even the most flawed.", notableWorks: ["Middlemarch", "The Mill on the Floss", "Daniel Deronda", "Adam Bede", "Silas Marner"], themes: ["Moral growth", "Community", "Idealism", "Women's lives", "Provincial life", "Sympathy"], influence: "Middlemarch set the standard for the realist novel and proved that fiction could be a vehicle for the deepest philosophical and moral thought.", funFact: "She lived openly with the married George Henry Lewes for 24 years, scandalizing Victorian society.", quotes: ["It is never too late to be what you might have been.", "The strongest principle of growth lies in human choice."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "nathaniel-hawthorne", name: "Nathaniel Hawthorne", birthYear: 1804, deathYear: 1864, birthPlace: "Salem, Massachusetts, USA", nationality: "American", era: "19th Century", traditions: ["American"], bio: "Nathaniel Hawthorne was America's first great novelist of moral complexity. The Scarlet Letter transforms a simple Puritan morality tale into a profound exploration of sin, guilt, identity, and the terrible cost of secrets. His other novels and tales return obsessively to the dark heritage of New England Puritanism.\n\nHawthorne's prose is dense with symbolism and allegory, yet his characters are fully human. He understood that moral questions are never simple and that the desire to judge others is itself one of the deepest sins.", notableWorks: ["The Scarlet Letter", "The House of the Seven Gables", "The Blithedale Romance", "Twice-Told Tales"], themes: ["Sin", "Guilt", "Puritanism", "Secrets", "Moral ambiguity", "The past"], influence: "Hawthorne established the American tradition of moral and psychological fiction that runs through James, Faulkner, and Morrison.", funFact: "He was a college friend of Franklin Pierce and wrote his campaign biography; Pierce made him consul to Liverpool.", quotes: ["No man can wear one face to himself and another to the multitude without finally getting bewildered.", "Happiness is a butterfly."], portraitPlaceholder: "linear-gradient(135deg, #143220, #0A1F14)" },
  { id: "henry-james", name: "Henry James", birthYear: 1843, deathYear: 1916, birthPlace: "New York City, USA", nationality: "American-British", era: "19th Century", traditions: ["Victorian", "Modernist"], bio: "Henry James was the master of the psychological novel, exploring the inner lives of his characters — particularly Americans encountering the complexities of European culture — with an unprecedented subtlety and precision. The Portrait of a Lady, The Wings of the Dove, The Ambassadors, and The Golden Bowl represent the summit of prose fiction's capacity to render consciousness.\n\nJames's late style, with its elaborate syntax and infinite qualifications, divides readers passionately. But for those attuned to it, no other novelist provides so rich and exact an experience of how human beings actually think, perceive, and choose.", notableWorks: ["The Portrait of a Lady", "The Turn of the Screw", "The Wings of the Dove", "The Ambassadors", "The Golden Bowl"], themes: ["Consciousness", "Americans in Europe", "Innocence and experience", "Art", "Morality", "Freedom"], influence: "James invented the modern psychological novel and influenced every subsequent novelist of consciousness from Woolf to Roth.", funFact: "He became a British citizen in 1915 as a protest against American neutrality in World War I.", quotes: ["Three things in human life are important: the first is to be kind, the second is to be kind, and the third is to be kind.", "It's a complex fate, being an American."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },

  // ── 19th Century European ──────────────────────────────────────────────────
  { id: "gustave-flaubert", name: "Gustave Flaubert", birthYear: 1821, deathYear: 1880, birthPlace: "Rouen, France", nationality: "French", era: "19th Century", traditions: ["French"], bio: "Gustave Flaubert devoted his life to finding le mot juste — the perfect word — and in Madame Bovary (1857) he produced the novel that Henry James called 'the most perfect and most famous of French novels.' Emma Bovary's destruction through romantic delusion became the defining portrait of bourgeois unhappiness.\n\nFlaubert's obsessive craftsmanship transformed the novel from entertainment into art. He spent five years on Bovary, sometimes writing a single page per week. His influence on Maupassant, James, Joyce, and Nabokov is immeasurable.", notableWorks: ["Madame Bovary", "Sentimental Education", "Salammbô", "Three Tales"], themes: ["Disillusionment", "Bourgeois life", "Art", "Style", "Romanticism", "Reality"], influence: "Flaubert established the modern novel as an art form and proved that the beauty of prose could coexist with unflinching realism.", funFact: "He was prosecuted for obscenity after Madame Bovary's serial publication but was acquitted.", quotes: ["Be regular and orderly in your daily life so that you may be violent and original in your work.", "Human speech is like a cracked kettle on which we tap crude rhythms for bears to dance to."], portraitPlaceholder: "linear-gradient(135deg, #0A1F3D, #061428)" },
  { id: "honor-de-balzac", name: "Honoré de Balzac", birthYear: 1799, deathYear: 1850, birthPlace: "Tours, France", nationality: "French", era: "19th Century", traditions: ["French"], bio: "Honoré de Balzac undertook one of the most ambitious projects in literary history: La Comédie Humaine, a vast interconnected series of over ninety novels and stories that together form a complete portrait of French society from the Restoration to the July Monarchy. Father Goriot, Lost Illusions, and Cousin Bette are among the greatest novels in any language.\n\nBalzac wrote with furious energy, often working eighteen hours a day fueled by coffee. His characters — the social climber Rastignac, the criminal mastermind Vautrin, the miser Grandet — have the mythic force of archetypes while remaining rooted in the specific details of Parisian life.", notableWorks: ["Father Goriot", "Lost Illusions", "Eugénie Grandet", "Cousin Bette"], themes: ["Ambition", "Money", "Society", "Passion", "Paris", "Human comedy"], influence: "Balzac created the modern social novel and the concept of recurring characters across linked works — anticipating Zola, Proust, and Faulkner.", funFact: "He consumed an estimated 50,000 cups of coffee during his career — sometimes 50 cups in a single writing session.", quotes: ["Behind every great fortune there is a crime.", "The motto of chivalry is also the motto of wisdom: to serve all, but love only one."], portraitPlaceholder: "linear-gradient(135deg, #0A1F3D, #061428)" },
  { id: "emile-zola", name: "Émile Zola", birthYear: 1840, deathYear: 1902, birthPlace: "Paris, France", nationality: "French", era: "19th Century", traditions: ["French"], bio: "Émile Zola was the father of literary naturalism and the author of the twenty-novel Rougon-Macquart cycle, which traces a family through France's Second Empire with the rigor of a scientist studying heredity and environment. Germinal, his novel of coal miners striking against impossible conditions, is the greatest working-class novel ever written.\n\nZola's famous open letter J'Accuse, defending the wrongly convicted Captain Dreyfus, made him the prototype of the engaged intellectual willing to risk everything for justice. He was forced into exile but lived to see Dreyfus pardoned.", notableWorks: ["Germinal", "Nana", "L'Assommoir", "Thérèse Raquin"], themes: ["Class", "Heredity", "Labor", "Naturalism", "Justice", "Society"], influence: "Zola founded literary naturalism and proved that the novel could serve as both scientific investigation and instrument of social justice.", funFact: "He died of carbon monoxide poisoning from a blocked chimney — some suspect it was deliberately blocked by a political enemy.", quotes: ["If you shut up truth and bury it under the ground, it will grow.", "I am here to live out loud."], portraitPlaceholder: "linear-gradient(135deg, #0A1F3D, #061428)" },
  { id: "ivan-turgenev", name: "Ivan Turgenev", birthYear: 1818, deathYear: 1883, birthPlace: "Oryol, Russia", nationality: "Russian", era: "19th Century", traditions: ["Russian"], bio: "Ivan Turgenev was the first Russian novelist to achieve international fame. Fathers and Children introduced the concept of nihilism to the world and depicted the generational conflict between Romantic idealists and materialist radicals with a sympathy for both sides that satisfied neither.\n\nHis Sportsman's Sketches, portraits of serfs and peasants drawn from his hunting expeditions, helped build the case for emancipation. Turgenev spent much of his life in Western Europe, and his elegant, measured prose style influenced Flaubert, James, and Chekhov.", notableWorks: ["Fathers and Children", "A Sportsman's Sketches", "On the Eve", "First Love"], themes: ["Generational conflict", "Russia", "Love", "Nihilism", "Nature", "Change"], influence: "Turgenev brought Russian literature to the world stage and created the template for the novel of ideas and generational conflict.", funFact: "He lived for years near the opera singer Pauline Viardot and her husband in one of literary history's most unusual domestic arrangements.", quotes: ["Nature is not a temple but a workshop.", "If we wait for the moment when everything is ready, we shall never begin."], portraitPlaceholder: "linear-gradient(135deg, #5C1A1A, #3D1010)" },
  { id: "henrik-ibsen", name: "Henrik Ibsen", birthYear: 1828, deathYear: 1906, birthPlace: "Skien, Norway", nationality: "Norwegian", era: "19th Century", traditions: ["Scandinavian"], bio: "Henrik Ibsen is called the father of modern drama. A Doll's House (1879) shook the Western world when Nora Helmer walked out on her husband and children, slamming the door heard round the world. Hedda Gabler, Ghosts, The Wild Duck, and An Enemy of the People followed, each dismantling the hypocrisies of bourgeois society.\n\nIbsen proved that the theater could address the urgent social and psychological questions of the age with the same seriousness as the novel. Every playwright since — Shaw, Chekhov, O'Neill, Miller — works in his shadow.", notableWorks: ["A Doll's House", "Hedda Gabler", "Ghosts", "An Enemy of the People", "The Wild Duck"], themes: ["Freedom", "Hypocrisy", "Women's rights", "Duty", "Truth", "Social criticism"], influence: "Ibsen reinvented Western drama and made the theater a forum for social criticism that it remains today.", funFact: "He kept a portrait of his rival Strindberg above his desk, saying it was good to have 'that madman' watching him while he worked.", quotes: ["A thousand words will not leave so deep an impression as one deed.", "The strongest man in the world is he who stands most alone."], portraitPlaceholder: "linear-gradient(135deg, #1E293B, #0F172A)" },

  // ── Modernist ──────────────────────────────────────────────────────────────
  { id: "g-k-chesterton", name: "G. K. Chesterton", birthYear: 1874, deathYear: 1936, birthPlace: "London, England", nationality: "English", era: "Early 20th Century", traditions: ["Victorian"], bio: "G. K. Chesterton was a paradoxist, essayist, novelist, and Catholic apologist whose Father Brown detective stories and metaphysical thriller The Man Who Was Thursday combine intellectual playfulness with profound spiritual vision. He wrote over a hundred books, thousands of essays, and debated everyone from Shaw to Wells.\n\nChesterton saw wonder in the ordinary and found the deepest truths hidden in paradox. His fiction treats ideas as adventures and transforms philosophical arguments into page-turning narratives.", notableWorks: ["The Man Who Was Thursday", "The Innocence of Father Brown", "Orthodoxy", "The Napoleon of Notting Hill"], themes: ["Paradox", "Faith", "Wonder", "Justice", "Humor", "Common sense"], influence: "Chesterton influenced Lewis, Tolkien, Borges, and Kafka with his paradoxical fiction and his defense of common-sense wonder against modern cynicism.", funFact: "He was so absent-minded that he once telegraphed his wife: Am in Market Harborough. Where ought I to be?", quotes: ["The true soldier fights not because he hates what is in front of him, but because he loves what is behind him.", "Fairy tales do not tell children the dragons exist. Children already know that dragons exist."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "aldous-huxley", name: "Aldous Huxley", birthYear: 1894, deathYear: 1963, birthPlace: "Godalming, Surrey, England", nationality: "English", era: "Early 20th Century", traditions: ["Modernist"], bio: "Aldous Huxley was a novelist, essayist, and intellectual whose Brave New World (1932) imagined a dystopia of comfort rather than cruelty — a world where humanity is enslaved not by tyranny but by pleasure, technology, and the eradication of suffering. It remains the most prescient dystopian novel ever written.\n\nHis early novels — Crome Yellow, Antic Hay, Point Counter Point — are brilliant satires of the 1920s intelligentsia. His later work explored mysticism, psychedelics, and the perennial philosophy. He died on the same day as C.S. Lewis and John F. Kennedy.", notableWorks: ["Brave New World", "Point Counter Point", "Crome Yellow", "The Doors of Perception"], themes: ["Dystopia", "Science", "Freedom", "Pleasure", "Consciousness", "Satire"], influence: "Brave New World defined the dystopian genre alongside Orwell's 1984 and remains frighteningly relevant to the age of social media and pharmaceutical happiness.", funFact: "On his deathbed, unable to speak, he wrote a note asking his wife to inject him with LSD.", quotes: ["Facts do not cease to exist because they are ignored.", "Maybe this world is another planet's hell."], portraitPlaceholder: "linear-gradient(135deg, #111827, #0A0F1A)" },
  { id: "evelyn-waugh", name: "Evelyn Waugh", birthYear: 1903, deathYear: 1966, birthPlace: "London, England", nationality: "English", era: "Early 20th Century", traditions: ["Modernist"], bio: "Evelyn Waugh was the funniest and most savage English novelist of the 20th century. Decline and Fall, Vile Bodies, and Scoop are masterpieces of social satire. Brideshead Revisited brought him a wider audience with its lyrical evocation of aristocratic Catholicism and lost youth.\n\nWaugh's prose is crystalline — every sentence lands with the precision of a sniper. His comic vision is simultaneously hilarious and despairing, revealing a world where civilization is a thin veneer over chaos.", notableWorks: ["Brideshead Revisited", "Decline and Fall", "A Handful of Dust", "Scoop", "Vile Bodies"], themes: ["Satire", "Catholicism", "Class", "Nostalgia", "Civilization", "Absurdity"], influence: "Waugh perfected the English comic novel and influenced every satirist from Amis to Wolfe.", funFact: "When told that Randolph Churchill was having a non-malignant tumor removed, he said: How typical — they cut the only part of Randolph that wasn't malignant.", quotes: ["Punctuality is the virtue of the bored.", "One forgets words as one forgets names."], portraitPlaceholder: "linear-gradient(135deg, #111827, #0A0F1A)" },
  { id: "e-m-forster", name: "E. M. Forster", birthYear: 1879, deathYear: 1970, birthPlace: "London, England", nationality: "English", era: "Early 20th Century", traditions: ["Modernist"], bio: "E. M. Forster wrote six novels, five of them before age 45, and each is a masterpiece of delicate moral intelligence. Howards End and A Passage to India explore the possibility of human connection across the barriers of class, culture, and empire with a sympathy that never simplifies.\n\nHis famous injunction 'Only connect' became a motto for an entire era. Forster believed that personal relationships are the only things that matter, and his novels test that belief against the forces of convention, imperialism, and fear.", notableWorks: ["A Passage to India", "Howards End", "A Room with a View", "Where Angels Fear to Tread", "Maurice"], themes: ["Connection", "Class", "Empire", "Culture clash", "Liberalism", "Personal relations"], influence: "Forster's humanist vision and his critique of imperialism remain touchstones for novelists exploring cross-cultural encounter.", funFact: "His novel Maurice, about a homosexual love affair, was published posthumously in 1971 because he felt England wasn't ready for it.", quotes: ["Only connect.", "How do I know what I think till I see what I say?"], portraitPlaceholder: "linear-gradient(135deg, #111827, #0A0F1A)" },

  // ── American ───────────────────────────────────────────────────────────────
  { id: "edith-wharton", name: "Edith Wharton", birthYear: 1862, deathYear: 1937, birthPlace: "New York City, USA", nationality: "American", era: "Early 20th Century", traditions: ["American"], bio: "Edith Wharton was the first woman to win the Pulitzer Prize for fiction and the supreme chronicler of old New York society. The Age of Innocence, The House of Mirth, and Ethan Frome dissect the cruelties of social convention with a surgical precision that masks profound compassion for her trapped characters.\n\nBorn into the wealthy class she anatomized, Wharton understood from the inside how privilege could become a prison. Her novels reveal the invisible bars of custom and expectation that confine even the most privileged lives.", notableWorks: ["The Age of Innocence", "The House of Mirth", "Ethan Frome", "The Custom of the Country"], themes: ["Society", "Convention", "Trapped lives", "New York", "Class", "Women's freedom"], influence: "Wharton perfected the novel of manners in American fiction and proved that the study of privilege could be as morally serious as the study of poverty.", funFact: "She was the first woman awarded the French Legion of Honor for her relief work during World War I.", quotes: ["There are two ways of spreading light: to be the candle or the mirror that reflects it.", "Life is the saddest thing there is, next to death."], portraitPlaceholder: "linear-gradient(135deg, #143220, #0A1F14)" },
  { id: "jack-london", name: "Jack London", birthYear: 1876, deathYear: 1916, birthPlace: "San Francisco, California, USA", nationality: "American", era: "Early 20th Century", traditions: ["American"], bio: "Jack London lived more adventure in forty years than most people manage in several lifetimes — oyster pirate, gold prospector, war correspondent, sailor, rancher, and socialist activist. His fiction draws on this raw experience with an elemental power that made him the best-selling American author of his era.\n\nThe Call of the Wild and White Fang use animal protagonists to explore primal questions about civilization and nature. Martin Eden is a devastating autobiographical novel about a self-educated writer destroyed by the very success he fought to achieve.", notableWorks: ["The Call of the Wild", "White Fang", "Martin Eden", "The Sea-Wolf", "The Iron Heel"], themes: ["Nature", "Survival", "Class", "Individualism", "Adventure", "Socialism"], influence: "London brought raw physical experience and socialist conviction to American fiction and became the prototype of the writer as adventurer.", funFact: "He was one of the first Americans to make a fortune from writing — and spent every cent as fast as he earned it.", quotes: ["The proper function of man is to live, not to exist.", "You can't wait for inspiration. You have to go after it with a club."], portraitPlaceholder: "linear-gradient(135deg, #143220, #0A1F14)" },
  { id: "willa-cather", name: "Willa Cather", birthYear: 1873, deathYear: 1947, birthPlace: "Gore, Virginia, USA", nationality: "American", era: "Early 20th Century", traditions: ["American"], bio: "Willa Cather was the great novelist of the American prairie. O Pioneers!, The Song of the Lark, and My Ántonia celebrate the immigrant families who settled the Great Plains with a spare, luminous prose that captures both the beauty and the harshness of the landscape.\n\nCather's aesthetic was one of simplification — she believed that the novel should be stripped of 'furniture' to reveal the essential emotional truth beneath. Her later novels, Death Comes for the Archbishop and The Professor's House, are among the most beautifully written works in American literature.", notableWorks: ["My Ántonia", "O Pioneers!", "Death Comes for the Archbishop", "The Song of the Lark"], themes: ["The prairie", "Immigration", "Art", "Memory", "Landscape", "Simplicity"], influence: "Cather established the literature of the American West and proved that the immigrant experience was a fit subject for great art.", funFact: "She ordered all her personal letters destroyed after her death, though many survived.", quotes: ["The end is nothing; the road is all.", "There are some things you learn best in calm, and some in storm."], portraitPlaceholder: "linear-gradient(135deg, #143220, #0A1F14)" },
  { id: "sinclair-lewis", name: "Sinclair Lewis", birthYear: 1885, deathYear: 1951, birthPlace: "Sauk Centre, Minnesota, USA", nationality: "American", era: "Early 20th Century", traditions: ["American"], bio: "Sinclair Lewis was the first American to win the Nobel Prize in Literature (1930), honored for Main Street, Babbitt, Arrowsmith, and Elmer Gantry — novels that satirized American small-town conformity, business culture, medicine, and religious hypocrisy with devastating accuracy.\n\nLewis had an uncanny ear for American speech and an ability to create characters who are simultaneously ridiculous and sympathetic. Babbitt became a common noun meaning a conformist businessman.", notableWorks: ["Main Street", "Babbitt", "Arrowsmith", "Elmer Gantry", "It Can't Happen Here"], themes: ["Conformity", "Small-town life", "American culture", "Satire", "Hypocrisy", "Business"], influence: "Lewis was the first novelist to map the spiritual emptiness of mainstream American life, paving the way for Updike, Cheever, and Franzen.", funFact: "He declined the Pulitzer Prize for Arrowsmith, calling it an attempt to make novels 'safe and polite.'", quotes: ["It is impossible to discourage the real writers.", "Intellectually I know that America is no better than any other country; emotionally I know she is better than every other country."], portraitPlaceholder: "linear-gradient(135deg, #143220, #0A1F14)" },
  { id: "frederick-douglass", name: "Frederick Douglass", birthYear: 1818, deathYear: 1895, birthPlace: "Cordova, Maryland, USA", nationality: "American", era: "19th Century", traditions: ["American"], bio: "Frederick Douglass escaped slavery and became the most powerful orator and writer in the American abolitionist movement. His Narrative of the Life of Frederick Douglass (1845) is both a searing indictment of slavery and a masterpiece of autobiography — direct, eloquent, and devastating in its moral clarity.\n\nDouglass's life refuted every pro-slavery argument simply by existing. He went on to become a newspaper editor, diplomat, and advisor to Abraham Lincoln, embodying the possibilities that slavery sought to destroy.", notableWorks: ["Narrative of the Life of Frederick Douglass", "My Bondage and My Freedom", "Life and Times of Frederick Douglass"], themes: ["Slavery", "Freedom", "Self-education", "Justice", "Human dignity", "Resistance"], influence: "Douglass's Narrative became the template for American autobiography and the most important document of the abolitionist movement.", funFact: "He taught himself to read by bribing white children with bread in exchange for lessons.", quotes: ["If there is no struggle, there is no progress.", "Once you learn to read, you will be forever free."], portraitPlaceholder: "linear-gradient(135deg, #143220, #0A1F14)" },
  { id: "w-e-b-du-bois", name: "W. E. B. Du Bois", birthYear: 1868, deathYear: 1963, birthPlace: "Great Barrington, Massachusetts, USA", nationality: "American", era: "Early 20th Century", traditions: ["American"], bio: "W. E. B. Du Bois was a sociologist, historian, and the preeminent Black intellectual of the 20th century. The Souls of Black Folk (1903) introduced the concept of 'double consciousness' — the experience of being both Black and American — and remains the foundational text of African American literature and thought.\n\nDu Bois co-founded the NAACP, edited The Crisis for 25 years, and spent his life fighting for racial justice through scholarship, activism, and art. His later works, including Darkwater and Black Reconstruction, expanded his analysis to encompass global colonialism.", notableWorks: ["The Souls of Black Folk", "Darkwater", "Black Reconstruction in America"], themes: ["Race", "Double consciousness", "Justice", "Education", "Pan-Africanism", "Democracy"], influence: "Du Bois shaped the intellectual framework for understanding race in America and globally, influencing every subsequent thinker on the subject.", funFact: "He was the first African American to earn a PhD from Harvard.", quotes: ["The problem of the twentieth century is the problem of the color line.", "Education is that whole system of human training."], portraitPlaceholder: "linear-gradient(135deg, #143220, #0A1F14)" },
  { id: "ernest-hemingway", name: "Ernest Hemingway", birthYear: 1899, deathYear: 1961, birthPlace: "Oak Park, Illinois, USA", nationality: "American", era: "Early 20th Century", traditions: ["Modernist"], bio: "Ernest Hemingway revolutionized English prose with a style stripped to its essentials — short sentences, concrete nouns, minimal adjectives, and a theory of omission that left the deepest meanings unstated. The Sun Also Rises, A Farewell to Arms, and The Old Man and the Sea defined a new aesthetic of masculine understatement.\n\nHis life — ambulance driver in Italy, journalist in Paris, big-game hunter in Africa, deep-sea fisherman in Cuba — became inseparable from his fiction. He won the Nobel Prize in 1954.", notableWorks: ["The Sun Also Rises", "A Farewell to Arms", "The Old Man and the Sea", "For Whom the Bell Tolls"], themes: ["War", "Masculinity", "Loss", "Courage", "The code hero", "Stoicism"], influence: "Hemingway transformed English prose style more radically than any writer since and made the 'iceberg theory' of omission a permanent technique.", funFact: "He survived two successive plane crashes in Africa in 1954 and read his own obituaries.", quotes: ["All you have to do is write one true sentence.", "The world breaks everyone, and afterward, some are strong at the broken places."], portraitPlaceholder: "linear-gradient(135deg, #143220, #0A1F14)" },
  { id: "william-faulkner", name: "William Faulkner", birthYear: 1897, deathYear: 1962, birthPlace: "New Albany, Mississippi, USA", nationality: "American", era: "Early 20th Century", traditions: ["Modernist", "American"], bio: "William Faulkner created Yoknapatawpha County, a fictional Mississippi realm populated with aristocrats, poor whites, and African Americans whose intertwined histories enact the entire tragedy of the American South. The Sound and the Fury, As I Lay Dying, Absalom, Absalom!, and Light in August are among the most technically innovative and emotionally devastating novels in any language.\n\nFaulkner's prose — dense, rhythmic, sometimes running for pages without a period — captures the way the past inhabits the present and the dead haunt the living. He won the Nobel Prize in 1949.", notableWorks: ["The Sound and the Fury", "As I Lay Dying", "Absalom, Absalom!", "Light in August"], themes: ["The South", "Race", "Time", "Decay", "Family", "Guilt"], influence: "Faulkner's experimental techniques and his creation of a mythic American landscape influenced García Márquez, Morrison, McCarthy, and the entire tradition of Southern literature.", funFact: "He worked as a Hollywood screenwriter to pay bills, contributing to films including The Big Sleep.", quotes: ["The past is never dead. It's not even past.", "I believe that man will not merely endure: he will prevail."], portraitPlaceholder: "linear-gradient(135deg, #143220, #0A1F14)" },

  // ── Children's Literature ──────────────────────────────────────────────────
  { id: "a-a-milne", name: "A. A. Milne", birthYear: 1882, deathYear: 1956, birthPlace: "London, England", nationality: "English", era: "Early 20th Century", traditions: ["Victorian"], bio: "A. A. Milne was a playwright and humorist who achieved immortality through Winnie-the-Pooh (1926) and The House at Pooh Corner (1928), inspired by his son Christopher Robin's stuffed animals. The Hundred Acre Wood is populated by characters — Pooh, Piglet, Eeyore, Tigger — who embody universal human temperaments with a warmth and wit that transcends children's literature.\n\nIronically, Milne came to resent being known only for Pooh, and his son Christopher Robin suffered his entire life from the fame thrust upon him as a child.", notableWorks: ["Winnie-the-Pooh", "The House at Pooh Corner", "Now We Are Six", "The Red House Mystery"], themes: ["Friendship", "Childhood", "Imagination", "Nature", "Simplicity", "Wisdom"], influence: "Milne created the most beloved animal characters in English literature and proved that children's books could contain real wisdom.", funFact: "Christopher Robin Milne said the fame from the books 'destroyed' his relationship with his father.", quotes: ["You are braver than you believe.", "Rivers know this: there is no hurry."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "frances-hodgson-burnett", name: "Frances Hodgson Burnett", birthYear: 1849, deathYear: 1924, birthPlace: "Manchester, England", nationality: "British-American", era: "19th Century", traditions: ["Victorian"], bio: "Frances Hodgson Burnett was born in England but raised in Tennessee, and her children's novels — Little Lord Fauntleroy, A Little Princess, and The Secret Garden — have never gone out of print. The Secret Garden is her masterpiece, a story of healing through nature that captures the transformative power of growth, both botanical and human.\n\nShe was one of the most commercially successful authors of her era, supporting an extravagant lifestyle through relentless writing.", notableWorks: ["The Secret Garden", "A Little Princess", "Little Lord Fauntleroy"], themes: ["Healing", "Nature", "Childhood", "Transformation", "Kindness", "Resilience"], influence: "Burnett's Secret Garden established the template for children's fiction about the healing power of nature.", funFact: "Little Lord Fauntleroy was so popular that it inspired a fashion craze for velvet suits with lace collars for boys.", quotes: ["If you look the right way, you can see that the whole world is a garden.", "Two things cannot be in one place. Where you tend a rose, a thistle cannot grow."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "carlo-collodi", name: "Carlo Collodi", birthYear: 1826, deathYear: 1890, birthPlace: "Florence, Italy", nationality: "Italian", era: "19th Century", traditions: ["Romantic"], bio: "Carlo Collodi was the pen name of Carlo Lorenzini, a Florentine journalist and satirist who wrote The Adventures of Pinocchio as a serial for a children's newspaper in 1881. Originally intended to end with the puppet's death by hanging, public demand forced Collodi to continue the story and give Pinocchio his redemption.\n\nThe original Pinocchio is far darker and more satirical than the Disney adaptation — a genuine morality tale about the consequences of laziness, disobedience, and credulity.", notableWorks: ["The Adventures of Pinocchio"], themes: ["Obedience", "Transformation", "Consequences", "Morality", "Childhood", "Truth"], influence: "Pinocchio is the most translated Italian book and one of the most famous fictional characters in the world.", funFact: "The original serial ended with Pinocchio being hanged — readers were so upset that Collodi had to resurrect him.", quotes: ["How ridiculous I was as a marionette!", "Lies have short legs."], portraitPlaceholder: "linear-gradient(135deg, #4A0E2D, #2D0819)" },
  { id: "rudyard-kipling", name: "Rudyard Kipling", birthYear: 1865, deathYear: 1936, birthPlace: "Bombay, India", nationality: "British", era: "19th Century", traditions: ["Victorian"], bio: "Rudyard Kipling was the youngest recipient of the Nobel Prize in Literature (1907) and the poet of the British Empire at its zenith. The Jungle Book, Kim, and Just So Stories are masterpieces of storytelling; his poetry — 'If,' 'Gunga Din,' 'Recessional' — remains among the most quoted in English.\n\nKipling is a deeply divided figure: his finest work shows extraordinary empathy across cultures and races, while his political writings championed imperialism. Kim, his greatest novel, captures India with a love and detail that transcend the politics of its author.", notableWorks: ["Kim", "The Jungle Book", "Just So Stories", "Captains Courageous"], themes: ["Empire", "India", "Adventure", "Duty", "Law", "Identity"], influence: "Kipling mastered every form from the novel to the short story to the ballad, and his influence on English prose and verse remains immense.", funFact: "He declined the Poet Laureateship, a knighthood, and the Order of Merit — but accepted the Nobel Prize.", quotes: ["If you can keep your head when all about you are losing theirs.", "Words are the most powerful drug used by mankind."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "e-nesbit", name: "E. Nesbit", birthYear: 1858, deathYear: 1924, birthPlace: "London, England", nationality: "English", era: "19th Century", traditions: ["Victorian"], bio: "E. Nesbit virtually invented the modern children's novel with The Story of the Treasure Seekers, Five Children and It, and The Railway Children. Her child characters speak and think like real children — funny, quarrelsome, imaginative, and occasionally selfish — a revolutionary departure from the goody-goody children of Victorian literature.\n\nShe was a founding member of the Fabian Society and lived a bohemian life that scandalized respectable society. C. S. Lewis, P. L. Travers, and J. K. Rowling all acknowledged her influence.", notableWorks: ["The Railway Children", "Five Children and It", "The Story of the Treasure Seekers"], themes: ["Childhood", "Magic", "Family", "Adventure", "Imagination", "Humor"], influence: "Nesbit invented the modern children's adventure novel and directly influenced Lewis, Tolkien, Travers, and Rowling.", funFact: "She raised her husband's illegitimate children alongside her own without telling anyone which was which.", quotes: ["It is wonderful how quickly you get used to things.", "There is a curtain, thin as gossamer, clear as glass, strong as iron, that hangs forever between the world of magic and the world that seems to us to be real."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "george-macdonald", name: "George MacDonald", birthYear: 1824, deathYear: 1905, birthPlace: "Huntly, Aberdeenshire, Scotland", nationality: "Scottish", era: "19th Century", traditions: ["Victorian"], bio: "George MacDonald was a Scottish minister and writer whose fairy tales and fantasies — The Princess and the Goblin, At the Back of the North Wind, Phantastes, Lilith — directly inspired C. S. Lewis, J. R. R. Tolkien, and the entire tradition of modern fantasy literature. Lewis called him his 'master' and said Phantastes 'baptized my imagination.'\n\nMacDonald's stories blend Christian allegory with genuine strangeness and beauty. They are never preachy — instead they create luminous worlds where spiritual truths are felt rather than stated.", notableWorks: ["The Princess and the Goblin", "Phantastes", "Lilith", "At the Back of the North Wind"], themes: ["Faith", "Imagination", "Good vs. evil", "Death", "Beauty", "Transformation"], influence: "MacDonald was the direct inspiration for Lewis and Tolkien and the most important precursor to modern fantasy literature.", funFact: "Lewis Carroll first showed the manuscript of Alice in Wonderland to MacDonald's children, whose enthusiasm convinced Carroll to publish it.", quotes: ["To be trusted is a greater compliment than to be loved.", "The best things are nearest: breath in your nostrils, light in your eyes."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },

  // ── Mystery & Detective ────────────────────────────────────────────────────
  { id: "agatha-christie", name: "Agatha Christie", birthYear: 1890, deathYear: 1976, birthPlace: "Torquay, Devon, England", nationality: "English", era: "Early 20th Century", traditions: ["Victorian"], bio: "Agatha Christie is the best-selling fiction writer of all time, with over two billion copies sold. Her detectives Hercule Poirot and Miss Marple are among the most beloved characters in literature, and her plots — particularly The Murder of Roger Ackroyd and And Then There Were None — revolutionized the mystery genre.\n\nChristie's genius lay in misdirection: she played fair with her readers, presenting all the clues, yet still surprised them at the end. Her theatrical background gave her an instinct for timing and revelation that no other mystery writer has matched.", notableWorks: ["The Murder of Roger Ackroyd", "And Then There Were None", "Murder on the Orient Express", "The Mysterious Affair at Styles"], themes: ["Murder", "Deduction", "Deception", "Justice", "English society", "Psychology"], influence: "Christie defined the golden age of detective fiction and remains the most widely read author in any genre.", funFact: "She disappeared for eleven days in 1926 in a mystery that has never been fully explained.", quotes: ["The impossible could not have happened, therefore the impossible must be possible.", "Every murderer is probably somebody's old friend."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "dorothy-l-sayers", name: "Dorothy L. Sayers", birthYear: 1893, deathYear: 1957, birthPlace: "Oxford, England", nationality: "English", era: "Early 20th Century", traditions: ["Victorian"], bio: "Dorothy L. Sayers created Lord Peter Wimsey, the most intellectually accomplished and emotionally complex of all golden-age detectives. Her novels — particularly Gaudy Night and The Nine Tailors — transcend the genre to become genuine literature, exploring class, gender, intellectual integrity, and the nature of vocation.\n\nSayers was also a distinguished translator of Dante's Divine Comedy and a Christian apologist whose theological essays remain widely read.", notableWorks: ["Gaudy Night", "The Nine Tailors", "Whose Body?", "Strong Poison"], themes: ["Justice", "Intellect", "Gender", "Class", "Vocation", "Love"], influence: "Sayers elevated detective fiction into a vehicle for serious intellectual and emotional exploration.", funFact: "She was one of the first women to receive a degree from Oxford, in 1920.", quotes: ["The only sin passion can commit is to be joyless.", "Trouble is like a sickness. It has to run its course."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "josephine-tey", name: "Josephine Tey", birthYear: 1896, deathYear: 1952, birthPlace: "Inverness, Scotland", nationality: "Scottish", era: "Early 20th Century", traditions: ["Victorian"], bio: "Josephine Tey was the pen name of Elizabeth Mackintosh, a Scottish playwright and novelist whose detective fiction transcends genre conventions. The Daughter of Time, in which a hospitalized detective investigates whether Richard III really murdered the princes in the Tower, is regularly voted the greatest mystery novel ever written.\n\nTey wrote only eight novels, each different from the last, united by psychological depth, beautiful prose, and a refusal to follow formula.", notableWorks: ["The Daughter of Time", "The Franchise Affair", "Brat Farrar", "The Man in the Queue"], themes: ["Justice", "History", "Identity", "Intuition", "Truth", "Scotland"], influence: "The Daughter of Time pioneered the historical mystery and showed that detective fiction could investigate the past itself.", funFact: "She was so private that few photographs of her exist and her death from cancer was a shock to even close friends.", quotes: ["The most popular thing in fiction is the wrongly accused.", "Truth isn't something you study. Truth is something you know."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "sheridan-le-fanu", name: "Sheridan Le Fanu", birthYear: 1814, deathYear: 1873, birthPlace: "Dublin, Ireland", nationality: "Irish", era: "19th Century", traditions: ["Victorian"], bio: "Sheridan Le Fanu was the master of Victorian supernatural fiction. His collection In a Glass Darkly includes Carmilla, the vampire novella that predates Dracula by twenty-five years and surpasses it in psychological subtlety. Uncle Silas and The House by the Churchyard are classic Gothic novels of menace and claustrophobia.\n\nLe Fanu wrote increasingly in seclusion after his wife's death, earning the nickname 'the invisible prince.' His influence on ghost story writers from M. R. James to Stephen King is profound.", notableWorks: ["In a Glass Darkly", "Uncle Silas", "The House by the Churchyard", "Carmilla"], themes: ["The supernatural", "Gothic", "Psychology", "Isolation", "Fear", "Death"], influence: "Le Fanu perfected the psychological ghost story and created the vampire tradition that Stoker would make famous.", funFact: "After his wife's death he became a recluse, writing through the night and rarely leaving his Dublin house.", quotes: ["There are some things too horrible for words.", "We live and breathe in a world of darkness."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "h-p-lovecraft", name: "H. P. Lovecraft", birthYear: 1890, deathYear: 1937, birthPlace: "Providence, Rhode Island, USA", nationality: "American", era: "Early 20th Century", traditions: ["American"], bio: "H. P. Lovecraft created cosmic horror — a genre in which the terror comes not from ghosts or demons but from the realization that the universe is vast, indifferent, and populated by entities beyond human comprehension. At the Mountains of Madness, The Call of Cthulhu, and The Case of Charles Dexter Ward established a mythology that has become one of the most influential in modern fiction.\n\nLovecraft published almost exclusively in pulp magazines and died in poverty, unaware that his work would become a cultural phenomenon. His personal racism is indefensible, but his literary influence — on Stephen King, Borges, Ligotti, and countless others — is undeniable.", notableWorks: ["At the Mountains of Madness", "The Call of Cthulhu", "The Case of Charles Dexter Ward", "The Shadow over Innsmouth"], themes: ["Cosmic horror", "Forbidden knowledge", "Madness", "The unknown", "Ancient beings", "Science"], influence: "Lovecraft invented cosmic horror and created a shared mythology that has permeated literature, film, games, and popular culture worldwide.", funFact: "He wrote over 100,000 letters in his lifetime — more than any other American author.", quotes: ["The oldest and strongest emotion of mankind is fear.", "We live on a placid island of ignorance in the midst of black seas of infinity."], portraitPlaceholder: "linear-gradient(135deg, #143220, #0A1F14)" },

  // ── Non-Fiction & Philosophy ────────────────────────────────────────────────
  { id: "charles-darwin", name: "Charles Darwin", birthYear: 1809, deathYear: 1882, birthPlace: "Shrewsbury, Shropshire, England", nationality: "English", era: "19th Century", traditions: ["Victorian"], bio: "Charles Darwin's On the Origin of Species (1859) is the most important scientific book ever written and one of the most beautifully argued. Darwin spent over twenty years accumulating evidence before publishing his theory of natural selection, and the book's patient, meticulous reasoning remains a model of scientific prose.\n\nThe Voyage of the Beagle, his account of the five-year journey that provided the raw material for his theory, is also a masterpiece of travel writing — vivid, curious, and unforgettable.", notableWorks: ["On the Origin of Species", "The Voyage of the Beagle", "The Descent of Man"], themes: ["Evolution", "Natural selection", "Nature", "Science", "Observation", "Time"], influence: "Darwin's theory of evolution by natural selection transformed humanity's understanding of life and its own place in nature.", funFact: "He waited twenty years to publish because he feared the religious and social consequences of his theory.", quotes: ["There is grandeur in this view of life.", "It is not the strongest that survives, but the most adaptable."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "friedrich-nietzsche", name: "Friedrich Nietzsche", birthYear: 1844, deathYear: 1900, birthPlace: "Röcken, Saxony, Prussia", nationality: "German", era: "19th Century", traditions: ["Germanic"], bio: "Friedrich Nietzsche was the most provocative philosopher of the modern era. His declaration that 'God is dead,' his concept of the Übermensch, and his critique of Christian morality as a 'slave revolt' in values permanently altered Western thought. Beyond Good and Evil, Thus Spake Zarathustra, and The Genealogy of Morals attack every comfortable assumption about truth, morality, and meaning.\n\nNietzsche wrote with a literary brilliance rare among philosophers — his aphorisms, parables, and rhetorical performances make his work simultaneously philosophy and literature.", notableWorks: ["Thus Spake Zarathustra", "Beyond Good and Evil", "The Genealogy of Morals", "Ecce Homo"], themes: ["Power", "Morality", "God", "Truth", "Will", "Eternal recurrence"], influence: "Nietzsche's ideas shaped existentialism, postmodernism, and virtually every intellectual movement of the 20th century.", funFact: "He collapsed in Turin after embracing a horse being beaten by its owner and never recovered his sanity.", quotes: ["He who has a why to live can bear almost any how.", "God is dead."], portraitPlaceholder: "linear-gradient(135deg, #1F2937, #111827)" },
  { id: "peter-kropotkin", name: "Peter Kropotkin", birthYear: 1842, deathYear: 1921, birthPlace: "Moscow, Russia", nationality: "Russian", era: "19th Century", traditions: ["Russian"], bio: "Prince Peter Kropotkin was a geographer, evolutionary theorist, and the most influential anarchist thinker in history. His Mutual Aid: A Factor of Evolution challenged Social Darwinism by demonstrating that cooperation, not competition, is the primary survival strategy in nature.\n\nThe Conquest of Bread laid out a practical vision of anarchist communism based on voluntary cooperation. Born a prince, he renounced his title and spent decades in prison and exile for his revolutionary activities.", notableWorks: ["Mutual Aid", "The Conquest of Bread", "Fields, Factories and Workshops", "Memoirs of a Revolutionist"], themes: ["Cooperation", "Anarchism", "Evolution", "Community", "Justice", "Nature"], influence: "Kropotkin provided the scientific and philosophical foundation for anarchist thought and challenged the individualist reading of Darwin.", funFact: "As a prince, he could have lived in luxury but chose prison and exile to fight for workers' freedom.", quotes: ["In the long run, the practice of solidarity proves much more advantageous to the species.", "The law is an adroit mixture of customs that are beneficial to society and could be followed even if no law existed."], portraitPlaceholder: "linear-gradient(135deg, #5C1A1A, #3D1010)" },
  { id: "olaudah-equiano", name: "Olaudah Equiano", birthYear: 1745, deathYear: 1797, birthPlace: "Essaka, Igboland (modern Nigeria)", nationality: "British-African", era: "Enlightenment", traditions: ["Enlightenment"], bio: "Olaudah Equiano's Interesting Narrative (1789) is the most important slave narrative of the 18th century and one of the foundational texts of African diaspora literature. Kidnapped from West Africa as a child, Equiano endured the Middle Passage, served multiple masters, educated himself, purchased his own freedom, and became a leading voice in the British abolitionist movement.\n\nHis account combines vivid personal testimony with reasoned argument against the slave trade, and it was instrumental in turning British public opinion toward abolition.", notableWorks: ["The Interesting Narrative of the Life of Olaudah Equiano"], themes: ["Slavery", "Freedom", "Identity", "Faith", "Commerce", "Human dignity"], influence: "Equiano's Narrative was the most widely read slave narrative of the 18th century and helped fuel the movement that abolished the British slave trade.", funFact: "He purchased his freedom for 40 pounds sterling — saved penny by penny from trading goods during his enslavement.", quotes: ["When you make men slaves, you compel them to live with you in a state of war.", "I had often seen my master and Dick employed in reading."], portraitPlaceholder: "linear-gradient(135deg, #0F2744, #091A2E)" },

  // ── Misc important authors ─────────────────────────────────────────────────
  { id: "lewis-carroll", name: "Lewis Carroll", birthYear: 1832, deathYear: 1898, birthPlace: "Daresbury, Cheshire, England", nationality: "English", era: "19th Century", traditions: ["Victorian"], bio: "Lewis Carroll was the pen name of Charles Lutwidge Dodgson, an Oxford mathematics lecturer who created Alice's Adventures in Wonderland and Through the Looking-Glass — two of the most original and enduring works of imagination in English. Alice's journey through a world of absurd logic, wordplay, and philosophical nonsense has influenced everyone from the Surrealists to computer scientists.\n\nCarroll was also a pioneer of photography, a skilled logician, and the inventor of numerous word games and puzzles.", notableWorks: ["Alice's Adventures in Wonderland", "Through the Looking-Glass", "The Hunting of the Snark", "Sylvie and Bruno"], themes: ["Nonsense", "Logic", "Childhood", "Identity", "Language", "Dreams"], influence: "Carroll invented literary nonsense and created the most famous child character in English literature, influencing surrealism, philosophy, and mathematics.", funFact: "Queen Victoria enjoyed Alice so much she asked for his next book — and received a treatise on determinants.", quotes: ["Begin at the beginning and go on till you come to the end: then stop.", "Why, sometimes I've believed as many as six impossible things before breakfast."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "george-bernard-shaw", name: "George Bernard Shaw", birthYear: 1856, deathYear: 1950, birthPlace: "Dublin, Ireland", nationality: "Irish", era: "19th Century", traditions: ["Victorian"], bio: "George Bernard Shaw was the most important English-language dramatist since Shakespeare. Over a career spanning six decades, he wrote more than sixty plays — Pygmalion, Man and Superman, Major Barbara, Saint Joan — that combined brilliant wit with serious intellectual argument. He used comedy as a weapon against poverty, war, hypocrisy, and conventional morality.\n\nShaw was awarded both the Nobel Prize in Literature (1925) and an Academy Award (for the screenplay of Pygmalion in 1938), making him the only person to win both.", notableWorks: ["Pygmalion", "Man and Superman", "Major Barbara", "Saint Joan", "Mrs. Warren's Profession"], themes: ["Social reform", "Wit", "Class", "War", "Evolution", "Feminism"], influence: "Shaw made the theater a forum for intellectual debate and social criticism, influencing every subsequent playwright of ideas.", funFact: "He is the only person to have won both a Nobel Prize and an Oscar.", quotes: ["Life isn't about finding yourself. Life is about creating yourself.", "The reasonable man adapts himself to the world; the unreasonable one persists in trying to adapt the world to himself."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "d-h-lawrence", name: "D. H. Lawrence", birthYear: 1885, deathYear: 1930, birthPlace: "Eastwood, Nottinghamshire, England", nationality: "English", era: "Early 20th Century", traditions: ["Modernist"], bio: "D. H. Lawrence was a novelist, poet, and essayist who championed the body, instinct, and emotional authenticity against what he saw as the deadening effects of industrialization and intellectual over-refinement. Sons and Lovers, The Rainbow, Women in Love, and Lady Chatterley's Lover explore sexuality and relationships with a frankness that repeatedly brought him into conflict with censors.\n\nLawrence's prose has a visceral, incantatory power that divides readers — some find it prophetic, others overwrought. But his influence on the novel's ability to represent physical and emotional experience is undeniable.", notableWorks: ["Sons and Lovers", "Women in Love", "The Rainbow", "Lady Chatterley's Lover"], themes: ["Sexuality", "Industry", "Nature", "Class", "Instinct", "Relationships"], influence: "Lawrence expanded the novel's capacity to represent the body and emotional life, influencing everyone from Miller to Lessing.", funFact: "Lady Chatterley's Lover was banned in Britain until 1960; the obscenity trial became a landmark of literary freedom.", quotes: ["The human soul needs beauty more than bread.", "I never saw a wild thing sorry for itself."], portraitPlaceholder: "linear-gradient(135deg, #111827, #0A0F1A)" },
  { id: "marcel-proust", name: "Marcel Proust", birthYear: 1871, deathYear: 1922, birthPlace: "Paris, France", nationality: "French", era: "Early 20th Century", traditions: ["Modernist", "French"], bio: "Marcel Proust spent the last fifteen years of his life in a cork-lined bedroom writing In Search of Lost Time, a seven-volume novel of approximately 1.5 million words that is widely considered the greatest achievement of 20th-century fiction. Beginning with the famous episode of the madeleine dipped in tea, the novel explores memory, time, art, love, jealousy, and the transformation of experience into literature.\n\nProust's sentences — immensely long, intricately qualified, and astonishingly precise — create a prose instrument capable of capturing the most fleeting sensations and the most complex social dynamics.", notableWorks: ["In Search of Lost Time"], themes: ["Memory", "Time", "Art", "Love", "Society", "Jealousy"], influence: "Proust's exploration of involuntary memory and subjective time transformed the novel into an instrument for recovering lived experience.", funFact: "He lined his bedroom with cork to block out noise and spent up to twenty hours a day in bed writing.", quotes: ["The real voyage of discovery consists not in seeking new landscapes, but in having new eyes.", "We are healed of a suffering only by experiencing it to the full."], portraitPlaceholder: "linear-gradient(135deg, #0A1F3D, #061428)" },
  { id: "james-fenimore-cooper", name: "James Fenimore Cooper", birthYear: 1789, deathYear: 1851, birthPlace: "Burlington, New Jersey, USA", nationality: "American", era: "19th Century", traditions: ["American"], bio: "James Fenimore Cooper was America's first major novelist. The Leatherstocking Tales — particularly The Last of the Mohicans and The Deerslayer — created the literary mythology of the American frontier and the archetype of the noble frontiersman caught between civilization and wilderness.\n\nCooper's novels were hugely popular in Europe as well as America, and their influence on the Western, the adventure novel, and the American self-image is incalculable, even though Mark Twain's famous essay on his literary offenses made mockery of his prose style fashionable.", notableWorks: ["The Last of the Mohicans", "The Deerslayer", "The Pathfinder", "The Pioneers"], themes: ["Frontier", "Race", "Wilderness", "Civilization", "Honor", "Loss"], influence: "Cooper created the myth of the American frontier and established the adventure novel as a vehicle for exploring national identity.", funFact: "Mark Twain wrote a devastatingly funny essay listing his literary offenses, but Cooper outsold Twain in Europe.", quotes: ["The tendency of democracies is to degenerate into despotisms.", "History, like love, is so apt to surround her heroes with an atmosphere of imaginary brightness."], portraitPlaceholder: "linear-gradient(135deg, #143220, #0A1F14)" },
  { id: "walt-whitman", name: "Walt Whitman", birthYear: 1819, deathYear: 1892, birthPlace: "West Hills, New York, USA", nationality: "American", era: "19th Century", traditions: ["American"], bio: "Walt Whitman's Leaves of Grass — first published in 1855 and revised throughout his life — is the founding text of American poetry. Writing in long, loose, inclusive lines that draw on the rhythms of the King James Bible and opera, Whitman celebrated democracy, the body, sexuality, nature, and the common American with an ecstatic voice that had no precedent.\n\nEmerson, reading the first edition, wrote: 'I greet you at the beginning of a great career.' Whitman continued to expand and revise Leaves of Grass for nearly four decades, making it the autobiography of both a man and a nation.", notableWorks: ["Leaves of Grass", "Song of Myself", "Drum-Taps"], themes: ["Democracy", "The body", "Nature", "America", "Sexuality", "Individuality"], influence: "Whitman reinvented English-language poetry and became the defining voice of American democratic culture.", funFact: "He self-published the first edition of Leaves of Grass, set some of the type himself, and wrote his own anonymous reviews.", quotes: ["I am large, I contain multitudes.", "Do I contradict myself? Very well then I contradict myself."], portraitPlaceholder: "linear-gradient(135deg, #143220, #0A1F14)" },
  { id: "edward-gibbon", name: "Edward Gibbon", birthYear: 1737, deathYear: 1794, birthPlace: "Putney, Surrey, England", nationality: "English", era: "Enlightenment", traditions: ["Enlightenment"], bio: "Edward Gibbon spent twenty years writing The History of the Decline and Fall of the Roman Empire, a work of over a million words that remains the most famous and most read historical narrative in English. His elegant, ironic prose and his controversial thesis — that Christianity contributed to Rome's fall — made the book both a literary masterpiece and a scandal.\n\nGibbon's Decline and Fall is the rare historical work that is read as much for pleasure as for instruction, and its influence on historians from Mommsen to Syme is matched by its influence on prose stylists from Austen to Churchill.", notableWorks: ["The History of the Decline and Fall of the Roman Empire", "Memoirs of My Life"], themes: ["Empire", "Decline", "Religion", "Power", "History", "Civilization"], influence: "Gibbon's Decline and Fall is the greatest historical narrative in English and established the modern discipline of historiography.", funFact: "He conceived the work while sitting among the ruins of the Capitol in Rome on October 15, 1764.", quotes: ["History is indeed little more than the register of the crimes and follies of mankind.", "The winds and waves are always on the side of the ablest navigators."], portraitPlaceholder: "linear-gradient(135deg, #0F2744, #091A2E)" },
  { id: "william-makepeace-thackeray", name: "William Makepeace Thackeray", birthYear: 1811, deathYear: 1863, birthPlace: "Calcutta, India", nationality: "English", era: "19th Century", traditions: ["Victorian"], bio: "William Makepeace Thackeray was Dickens's great rival and the author of Vanity Fair, the most brilliantly cynical novel of the Victorian era. Subtitled 'A Novel Without a Hero,' it follows the fortunes of the scheming Becky Sharp and the virtuous Amelia Sedley through Regency England and the Napoleonic Wars.\n\nThackeray's satirical vision is more coolly devastating than Dickens's emotional approach, and his narrator's ironic commentary anticipates modern fiction's self-consciousness about storytelling itself.", notableWorks: ["Vanity Fair", "The History of Henry Esmond", "Pendennis", "Barry Lyndon"], themes: ["Vanity", "Social climbing", "Satire", "War", "Class", "Hypocrisy"], influence: "Vanity Fair established the novel of social satire without a conventional hero, influencing every subsequent satirist from Waugh to Wolfe.", funFact: "He illustrated many of his own novels and was a skilled caricaturist.", quotes: ["The world is a looking-glass, and gives back to every man the reflection of his own face.", "Mother is the name for God in the lips and hearts of little children."], portraitPlaceholder: "linear-gradient(135deg, #2D1B5E, #1E1145)" },
  { id: "louisa-may-alcott", name: "Louisa May Alcott", birthYear: 1832, deathYear: 1888, birthPlace: "Germantown, Pennsylvania, USA", nationality: "American", era: "19th Century", traditions: ["American"], bio: "Louisa May Alcott wrote Little Women (1868), the novel that redefined American girlhood and remains one of the most beloved books in English. Based on her own family, the story of the four March sisters growing up during the Civil War captures the tensions between ambition and domesticity, independence and duty, with an honesty that still resonates.\n\nBefore Little Women made her famous, Alcott supported her family by writing sensational thrillers under a pseudonym — tales of femmes fatales and opium dens that were only rediscovered a century later.", notableWorks: ["Little Women", "Little Men", "Jo's Boys", "Hospital Sketches"], themes: ["Family", "Ambition", "Women's lives", "Duty", "Poverty", "Growth"], influence: "Little Women established the domestic novel for young readers and made Jo March the prototype of the ambitious American girl.", funFact: "She wrote blood-and-thunder thrillers under the pen name A.M. Barnard — they were only rediscovered in 1975.", quotes: ["I am not afraid of storms, for I am learning how to sail my ship.", "I'd rather take coffee than compliments just now."], portraitPlaceholder: "linear-gradient(135deg, #143220, #0A1F14)" },
  { id: "john-bunyan", name: "John Bunyan", birthYear: 1628, deathYear: 1688, birthPlace: "Elstow, Bedfordshire, England", nationality: "English", era: "Renaissance", traditions: ["Renaissance"], bio: "John Bunyan was a tinker and lay preacher who spent twelve years in prison for unlicensed preaching and there wrote The Pilgrim's Progress (1678), the most widely read religious allegory ever written and, after the Bible, the best-selling English book for three centuries.\n\nChristian's journey from the City of Destruction to the Celestial City, passing through the Slough of Despond, Vanity Fair, and Doubting Castle, created images and phrases that entered the language itself.", notableWorks: ["The Pilgrim's Progress", "Grace Abounding", "The Holy War"], themes: ["Faith", "Salvation", "Temptation", "Perseverance", "Allegory", "Pilgrimage"], influence: "The Pilgrim's Progress is the most influential allegory in English and shaped the novel's development from Defoe to Thackeray.", funFact: "He wrote Pilgrim's Progress in Bedford jail, using its stone walls as inspiration for Doubting Castle.", quotes: ["You have not lived today until you have done something for someone who can never repay you.", "In prayer it is better to have a heart without words than words without a heart."], portraitPlaceholder: "linear-gradient(135deg, #3D1A6E, #2A1050)" },
  { id: "thomas-malory", name: "Thomas Malory", birthYear: 1415, deathYear: 1471, birthPlace: "Warwickshire, England (probably)", nationality: "English", era: "Medieval", traditions: ["Medieval European"], bio: "Sir Thomas Malory wrote Le Morte d'Arthur while in prison, producing the definitive English version of the Arthurian legends. Published by William Caxton in 1485, it gathered the scattered French and English romances of King Arthur, the Round Table, the Holy Grail, and the love of Lancelot and Guinevere into a single magnificent narrative.\n\nLe Morte d'Arthur established the Arthurian legend as we know it and remains the primary source for virtually every subsequent retelling, from Tennyson to T.H. White to Monty Python.", notableWorks: ["Le Morte d'Arthur"], themes: ["Chivalry", "Honor", "Love", "Betrayal", "The Grail", "The fall of Camelot"], influence: "Malory fixed the Arthurian legend in its definitive form and provided the source material for all subsequent Arthurian literature.", funFact: "He was imprisoned for a remarkable variety of crimes including cattle theft, extortion, and ambushing the Duke of Buckingham.", quotes: ["Who pulleth out this sword of this stone and anvil is rightwise King born of all England.", "The joy of love is too short, and the sorrow thereof is over long."], portraitPlaceholder: "linear-gradient(135deg, #1B4332, #0F2B20)" },
  { id: "mary-wollstonecraft", name: "Mary Wollstonecraft", birthYear: 1759, deathYear: 1797, birthPlace: "London, England", nationality: "English", era: "Enlightenment", traditions: ["Enlightenment"], bio: "Mary Wollstonecraft wrote A Vindication of the Rights of Woman (1792), the foundational text of modern feminism. Responding to Rousseau's claim that women should be educated only to please men, she argued that women are rational beings deserving the same education and rights as men.\n\nHer life was as radical as her ideas: she traveled alone to revolutionary Paris, had a daughter out of wedlock, attempted suicide twice, and died at thirty-eight giving birth to her second daughter — Mary Shelley, who would write Frankenstein.", notableWorks: ["A Vindication of the Rights of Woman", "A Vindication of the Rights of Men", "Maria"], themes: ["Women's rights", "Education", "Reason", "Freedom", "Equality", "Independence"], influence: "Wollstonecraft launched the modern feminist tradition and established the argument for women's rational equality that would fuel centuries of reform.", funFact: "Her daughter Mary Shelley wrote Frankenstein, and her granddaughter was a suffragist — three generations of radical women.", quotes: ["I do not wish women to have power over men, but over themselves.", "Strengthen the female mind by enlarging it."], portraitPlaceholder: "linear-gradient(135deg, #0F2744, #091A2E)" },
  { id: "harriet-beecher-stowe", name: "Harriet Beecher Stowe", birthYear: 1811, deathYear: 1896, birthPlace: "Litchfield, Connecticut, USA", nationality: "American", era: "19th Century", traditions: ["American"], bio: "Harriet Beecher Stowe wrote Uncle Tom's Cabin (1852), the novel that Abraham Lincoln reportedly said started the Civil War. Serialized in an abolitionist newspaper, it became the best-selling novel of the 19th century and galvanized Northern opposition to slavery with its vivid portrayal of enslaved people's suffering and humanity.\n\nThe novel's power lies in its appeal to empathy — Stowe made readers feel what slavery meant in human terms. Its cultural impact was unprecedented and has rarely been equaled by any single work of fiction.", notableWorks: ["Uncle Tom's Cabin", "Dred", "The Minister's Wooing"], themes: ["Slavery", "Faith", "Family", "Justice", "Empathy", "Resistance"], influence: "Uncle Tom's Cabin was the most politically influential American novel ever written and helped precipitate the Civil War.", funFact: "Lincoln allegedly greeted her with: So you're the little woman who wrote the book that started this great war.", quotes: ["The longest way must have its close.", "Never give up, for that is just the place and time that the tide will turn."], portraitPlaceholder: "linear-gradient(135deg, #143220, #0A1F14)" },
  { id: "thomas-mann", name: "Thomas Mann", birthYear: 1875, deathYear: 1955, birthPlace: "Lübeck, Germany", nationality: "German", era: "Early 20th Century", traditions: ["Germanic"], bio: "Thomas Mann was awarded the Nobel Prize in 1929, primarily for Buddenbrooks, his first novel and a masterpiece chronicling the decline of a mercantile family over four generations. The Magic Mountain, set in a Swiss tuberculosis sanatorium, became a vast allegory of European civilization before World War I.\n\nMann's prose is elaborate, ironic, and deeply musical. His lifelong themes — the tension between the bourgeois and the artistic temperament, between health and disease, between Germany and the West — gave his novels an intellectual depth matched by few other writers.", notableWorks: ["Buddenbrooks", "The Magic Mountain", "Doctor Faustus", "Death in Venice"], themes: ["Decline", "Art vs. life", "Germany", "Disease", "Time", "Bourgeois culture"], influence: "Mann is the supreme novelist of ideas in the German language, and his exploration of culture and barbarism remains urgently relevant.", funFact: "He fled Nazi Germany in 1933 and eventually settled in California, where he became an American citizen.", quotes: ["A writer is somebody for whom writing is more difficult than it is for other people.", "Time cools, time clarifies."], portraitPlaceholder: "linear-gradient(135deg, #1F2937, #111827)" },
  { id: "hermann-hesse", name: "Hermann Hesse", birthYear: 1877, deathYear: 1962, birthPlace: "Calw, Württemberg, Germany", nationality: "German-Swiss", era: "Early 20th Century", traditions: ["Germanic"], bio: "Hermann Hesse won the Nobel Prize in 1946 for novels that explore the individual's search for authenticity and spiritual fulfillment. Siddhartha, Steppenwolf, and The Glass Bead Game each follows a protagonist torn between the life of the mind and the life of the senses, between Eastern wisdom and Western restlessness.\n\nHesse became a countercultural icon in the 1960s, when millions of young readers discovered in his novels a guide to self-discovery that transcended both Eastern and Western traditions.", notableWorks: ["Siddhartha", "Steppenwolf", "The Glass Bead Game", "Demian"], themes: ["Self-discovery", "Duality", "Eastern philosophy", "Art", "Individuality", "Spiritual search"], influence: "Hesse bridged Eastern and Western thought in fiction and became the most widely read German author of the 20th century.", funFact: "He became a Swiss citizen in 1924 and spent his last decades in a village in Ticino, painting watercolors.", quotes: ["I have been and still am a seeker, but I have ceased to question stars and books.", "Some of us think holding on makes us strong, but sometimes it is letting go."], portraitPlaceholder: "linear-gradient(135deg, #1F2937, #111827)" },

  // ── Anonymous/Unknown ──────────────────────────────────────────────────────
  { id: "anonymous", name: "Anonymous", birthPlace: "Various", nationality: "Various", era: "Various", traditions: ["Various"], bio: "Many of the world's greatest literary works were composed by authors whose names have been lost to history, or were the product of oral traditions that resist individual attribution. From ancient epics to medieval romances to folk tales, these works remind us that literature has always been a collective as well as an individual achievement.\n\nThe convention of attributing works to 'Anonymous' encompasses a vast range of periods, cultures, and genres — united only by the absence of a known author and the enduring power of the work itself.", notableWorks: ["Beowulf", "The Nibelungenlied", "Sir Gawain and the Green Knight", "The Arabian Nights"], themes: ["Oral tradition", "Collective authorship", "Myth", "Legend", "Folk wisdom"], influence: "Anonymous works form the bedrock of every literary tradition, preserving the stories that cultures told to define themselves.", funFact: "Virginia Woolf observed that 'Anonymous' was often a woman, denied credit for her creations.", quotes: ["The author is unknown, but the story endures.", "Every culture speaks through its anonymous voices."], portraitPlaceholder: "linear-gradient(135deg, #374151, #1F2937)" },
  { id: "unknown-beowulf", name: "The Beowulf Poet", birthPlace: "England (Anglo-Saxon)", nationality: "Anglo-Saxon", era: "Medieval", traditions: ["Medieval European"], bio: "The anonymous author of Beowulf composed the greatest surviving work of Old English literature sometime between the 8th and early 11th centuries. The poem tells of a Scandinavian hero who travels to Denmark to slay the monster Grendel and his mother, then returns home to rule for fifty years before dying in combat with a dragon.\n\nBeowulf blends pagan heroic values with Christian themes in a way that suggests a poet deeply aware of living between two worlds. J. R. R. Tolkien's landmark 1936 essay 'Beowulf: The Monsters and the Critics' rescued the poem from purely historical study and revealed its literary greatness.", notableWorks: ["Beowulf"], themes: ["Heroism", "Mortality", "Monsters", "Loyalty", "Fate", "Legacy"], influence: "Beowulf is the foundation of English literature and directly inspired Tolkien's creation of Middle-earth.", funFact: "The only surviving manuscript nearly burned in a 1731 fire at Ashburnham House.", quotes: ["Fate often saves an undoomed man when his courage is good.", "Each of us must face the end of life in this world."], portraitPlaceholder: "linear-gradient(135deg, #1B4332, #0F2B20)" },
];

// ── Main ───────────────────────────────────────────────────────────────────────

function main() {
  let authorsContent = fs.readFileSync(AUTHORS_FILE, "utf-8");

  // Extract existing author IDs
  const existingIds = new Set<string>();
  const idRegex = /id:\s*"([^"]+)"/g;
  let match: RegExpExecArray | null;
  while ((match = idRegex.exec(authorsContent)) !== null) {
    existingIds.add(match[1]);
  }

  console.log(`Found ${existingIds.size} existing authors in authors.ts`);

  let added = 0;
  let skipped = 0;
  const newEntries: string[] = [];

  for (const a of AUTHORS) {
    if (existingIds.has(a.id)) {
      skipped++;
      continue;
    }

    let entry = `  {\n`;
    entry += `    id: "${a.id}",\n`;
    entry += `    name: "${a.name.replace(/"/g, '\\"')}",\n`;
    if (a.birthYear !== undefined) entry += `    birthYear: ${a.birthYear},\n`;
    if (a.deathYear !== undefined) entry += `    deathYear: ${a.deathYear},\n`;
    entry += `    birthPlace: "${a.birthPlace.replace(/"/g, '\\"')}",\n`;
    entry += `    nationality: "${a.nationality}",\n`;
    entry += `    era: "${a.era}",\n`;
    entry += `    traditions: [${a.traditions.map(t => `"${t}"`).join(", ")}],\n`;
    entry += `    bio: ${JSON.stringify(a.bio)},\n`;
    entry += `    notableWorks: [${a.notableWorks.map(w => `"${w.replace(/"/g, '\\"')}"`).join(", ")}],\n`;
    entry += `    themes: [${a.themes.map(t => `"${t}"`).join(", ")}],\n`;
    entry += `    influence: "${a.influence.replace(/"/g, '\\"')}",\n`;
    entry += `    funFact: "${a.funFact.replace(/"/g, '\\"')}",\n`;
    entry += `    quotes: [\n${a.quotes.map(q => `      "${q.replace(/"/g, '\\"')}"`).join(",\n")}\n    ],\n`;
    entry += `    portraitPlaceholder: "${a.portraitPlaceholder}",\n`;
    entry += `  }`;

    newEntries.push(entry);
    added++;
  }

  if (newEntries.length > 0) {
    const insert = ",\n\n  // ── ADDITIONAL AUTHORS (auto-generated) ─────────────────────────────────────\n\n" +
      newEntries.join(",\n");

    // Find the closing `]` of the AUTHORS array (before helper functions)
    const helperIdx = authorsContent.indexOf("// ── Helper Functions");
    if (helperIdx === -1) {
      console.error("ERROR: Could not find Helper Functions marker in authors.ts");
      process.exit(1);
    }

    // Find the `]` before the helper functions
    const closeIdx = authorsContent.lastIndexOf("]", helperIdx);
    if (closeIdx === -1) {
      console.error("ERROR: Could not find closing `]` before Helper Functions");
      process.exit(1);
    }

    authorsContent = authorsContent.slice(0, closeIdx) + insert + "\n" + authorsContent.slice(closeIdx);
    fs.writeFileSync(AUTHORS_FILE, authorsContent, "utf-8");
    console.log(`\nWrote ${added} new authors to authors.ts`);
  }

  console.log("\n══════════════════════════════════════════════════════");
  console.log(`  AUTHORS SUMMARY`);
  console.log(`  Added:   ${added}`);
  console.log(`  Skipped: ${skipped} (already existed)`);
  console.log("══════════════════════════════════════════════════════\n");
}

main();
